import type { SplitResult } from './chunker.js';

const EXT_TO_LANG: Record<string, string> = {
  '.ts': 'typescript',
  '.tsx': 'typescript',
  '.mts': 'typescript',
  '.cts': 'typescript',
  '.js': 'javascript',
  '.jsx': 'javascript',
  '.mjs': 'javascript',
  '.cjs': 'javascript',
  '.py': 'python',
  '.rs': 'rust',
  '.go': 'go',
  '.java': 'java',
  '.json': 'json',
  '.yaml': 'yaml',
  '.yml': 'yaml',
  '.md': 'markdown',
  '.sql': 'sql',
  '.sh': 'shell',
  '.css': 'css',
  '.html': 'html',
};

const LANGUAGE_ALIASES: Record<string, string> = {
  cjs: 'javascript',
  cts: 'typescript',
  js: 'javascript',
  jsx: 'javascript',
  md: 'markdown',
  mjs: 'javascript',
  mts: 'typescript',
  py: 'python',
  rs: 'rust',
  sh: 'shell',
  ts: 'typescript',
  tsx: 'typescript',
  yml: 'yaml',
};

export function inferLanguageFromPath(filePath: string): string | undefined {
  return EXT_TO_LANG[extname(normalizeContextPath(filePath)).toLowerCase()];
}

export function normalizeLanguage(language?: string): string | undefined {
  const normalized = language?.trim().toLowerCase();
  if (!normalized) return undefined;
  return LANGUAGE_ALIASES[normalized] ?? normalized;
}

export function normalizeContextPath(filePath: string): string {
  const slashed = filePath.split(/[\\/]+/).join('/');
  const normalized = posix.normalize(slashed);
  return normalized === '.' ? '' : normalized;
}

export interface IngestResult {
  /** The primary chunk (parent if split, otherwise the chunk itself) */
  primary: ContextChunk;
  /** Full split result if chunking occurred, null otherwise */
  split: SplitResult | null;
}

export class ContextIngester {
  constructor(
    private tokenEstimator: TokenEstimator,
    private chunkingConfig = DEFAULT_CHUNKING_CONFIG
  ) {}

  /** Ingest text, auto-splitting if oversized. Returns primary chunk + split info. */
  ingestText(source: string, text: string, type?: ChunkType): IngestResult {
    const resolvedType = type ?? classifyChunk(text, source);
    const tokensEstimate = this.tokenEstimator.estimate(text);
    const split = maybeSplit(text, tokensEstimate, this.chunkingConfig, this.tokenEstimator, {
      source,
      type: resolvedType,
    });
    if (split) return { primary: split.parent, split };
    return {
      primary: {
        id: randomUUID(),
        source,
        type: resolvedType,
        text,
        timestamp: Date.now(),
        tokensEstimate,
        childrenIds: [],
        metadata: {},
      },
      split: null,
    };
  }

  /**
   * Async version that uses tree-sitter when CHUNK_TREE_SITTER=1.
   * Falls back to sync regex-based splitting if tree-sitter is unavailable.
   */
  async ingestTextAsync(source: string, text: string, type?: ChunkType): Promise<IngestResult> {
    const resolvedType = type ?? classifyChunk(text, source);
    const tokensEstimate = this.tokenEstimator.estimate(text);
    const split = await maybeSplitAsync(text, tokensEstimate, this.chunkingConfig, this.tokenEstimator, {
      source,
      type: resolvedType,
    });
    if (split) return { primary: split.parent, split };
    return {
      primary: {
        id: randomUUID(),
        source,
        type: resolvedType,
        text,
        timestamp: Date.now(),
        tokensEstimate,
        childrenIds: [],
        metadata: {},
      },
      split: null,
    };
  }

  ingestFile(
    filePath: string,
    content: string,
    language?: string,
    overrideType?: ChunkType
  ): IngestResult {
    const normalizedPath = normalizeContextPath(filePath);
    const lang = normalizeLanguage(language) ?? inferLanguageFromPath(normalizedPath);
    const type = overrideType ?? (classifyChunk(content, 'file') as ChunkType);
    const tokensEstimate = this.tokenEstimator.estimate(content);
    const split = maybeSplit(content, tokensEstimate, this.chunkingConfig, this.tokenEstimator, {
      source: 'file',
      type,
      path: normalizedPath,
      language: lang,
    });
    if (split) return { primary: split.parent, split };
    return {
      primary: {
        id: randomUUID(),
        source: 'file',
        type,
        text: content,
        timestamp: Date.now(),
        path: normalizedPath,
        language: lang,
        tokensEstimate,
        childrenIds: [],
        metadata: {},
      },
      split: null,
    };
  }

  /**
   * Async version that uses tree-sitter when CHUNK_TREE_SITTER=1.
   * Falls back to sync regex-based splitting if tree-sitter is unavailable.
   */
  async ingestFileAsync(
    filePath: string,
    content: string,
    language?: string,
    overrideType?: ChunkType
  ): Promise<IngestResult> {
    const normalizedPath = normalizeContextPath(filePath);
    const lang = normalizeLanguage(language) ?? inferLanguageFromPath(normalizedPath);
    const type = overrideType ?? (classifyChunk(content, 'file') as ChunkType);
    const tokensEstimate = this.tokenEstimator.estimate(content);
    const split = await maybeSplitAsync(content, tokensEstimate, this.chunkingConfig, this.tokenEstimator, {
      source: 'file',
      type,
      path: normalizedPath,
      language: lang,
    });
    if (split) return { primary: split.parent, split };
    return {
      primary: {
        id: randomUUID(),
        source: 'file',
        type,
        text: content,
        timestamp: Date.now(),
        path: normalizedPath,
        language: lang,
        tokensEstimate,
        childrenIds: [],
        metadata: {},
      },
      split: null,
    };
  }

  ingestDiff(diffText: string): ContextChunk {
    return {
      id: randomUUID(),
      source: 'diff',
      type: 'diff',
      text: diffText,
      timestamp: Date.now(),
      tokensEstimate: this.tokenEstimator.estimate(diffText),
      childrenIds: [],
      metadata: {},
    };
  }

  ingestConversation(
    messages: { role: string; content: string }[]
  ): ContextChunk[] {
    return messages.map((msg) => {
      const source = 'conversation';
      const type = classifyChunk(msg.content, source) as ChunkType;
      return {
        id: randomUUID(),
        source,
        type,
        text: msg.content,
        timestamp: Date.now(),
        tokensEstimate: this.tokenEstimator.estimate(msg.content),
        childrenIds: [],
        metadata: { role: msg.role },
      };
    });
  }

  ingestDirectory(
    basePath: string,
    files: { path: string; content: string }[]
  ): IngestResult[] {
    return files.map((f) =>
      this.ingestFile(`${normalizeContextPath(basePath)}/${normalizeContextPath(f.path)}`, f.content)
    );
  }
}

import type { RetrievalStrategy, StructuralQuery } from '../types/index.js';
import { normalizeIdentifier, normalizeSymbolName, splitIdentifier } from '../providers/structural-indexer.js';

export type QueryIntent = 'code_search' | 'debug' | 'explain' | 'implement' | 'general';

export interface QueryPlan {
  intent: QueryIntent;
  expandedTerms: string[];
  strategy: RetrievalStrategy;
  maxHops: number;
  tokenBudgetRatio: number; // fraction of max tokens to use
  complexity: 'narrow' | 'moderate' | 'broad'; // query scope estimate
  structuralQuery: StructuralQuery;
  recommendedTopK: number;
}

const INTENT_KEYWORDS: Record<QueryIntent, string[]> = {
  debug: ['error', 'bug', 'fail', 'crash', 'broken', 'fix', 'issue', 'exception', 'trace', 'wrong', 'unexpected'],
  implement: ['add', 'create', 'build', 'implement', 'write', 'make', 'new', 'feature', 'support', 'switch', 'update', 'change', 'modify', 'enhance'],
  explain: ['how', 'why', 'what', 'explain', 'understand', 'describe', 'meaning', 'purpose', 'does'],
  code_search: ['where', 'find', 'locate', 'search', 'show', 'grep', 'file', 'function', 'class', 'module'],
  general: [],
};

const MUTATION_TERMS = new Set([
  'add', 'build', 'change', 'create', 'enhance', 'extend', 'implement',
  'improve', 'make', 'modify', 'refactor', 'switch', 'update', 'write',
]);

const LOOKUP_OPENING = /^(where|find|locate|show|grep|which\s+file)\b/i;

// Broadening signals: queries mentioning "all", "entire", "everything", "whole" suggest wider scope
const BROADENING_TERMS = new Set([
  'all', 'entire', 'everything', 'whole', 'comprehensive', 'complete',
  'full', 'overall', 'architecture', 'system', 'overview', 'every',
  'multiple', 'various', 'several',
]);

// Narrowing signals: queries with specific file paths, function names, or "exact" language
const NARROWING_TERMS = new Set([
  'exact', 'specific', 'only', 'just', 'single', 'one', 'this',
  'precise', 'particular',
]);

/** Detect the primary intent of a query */
export function detectIntent(query: string): QueryIntent {
  const lower = query.toLowerCase();
  const words = lower.split(/\s+/);

  if (!LOOKUP_OPENING.test(lower) && words.some((word) => MUTATION_TERMS.has(word))) {
    return 'implement';
  }

  let bestIntent: QueryIntent = 'general';
  let bestScore = 0;

  for (const [intent, keywords] of Object.entries(INTENT_KEYWORDS)) {
    let score = 0;
    for (const keyword of keywords) {
      // Word-boundary match only. Substring matching produced false positives
      // ("show" contains "how", "prefix" contains "fix") that polluted intent.
      if (words.includes(keyword)) score += 2;
    }
    if (score > bestScore) {
      bestScore = score;
      bestIntent = intent as QueryIntent;
    }
  }

  return bestIntent;
}

const STOP_WORDS = new Set([
    'the', 'a', 'an', 'is', 'are', 'was', 'were', 'be', 'been', 'being',
    'have', 'has', 'had', 'do', 'does', 'did', 'will', 'would', 'could',
    'should', 'may', 'might', 'shall', 'can', 'need', 'dare', 'ought',
    'used', 'to', 'of', 'in', 'for', 'on', 'with', 'at', 'by', 'from',
    'it', 'its', 'this', 'that', 'these', 'those', 'i', 'me', 'my', 'we',
    'how', 'why', 'what', 'who', 'when', 'where', 'which', 'than', 'then',
    'please', 'using', 'use', 'uses', 'used', 'add', 'fix', 'find',
  ]);

/** Extract key terms from a query for expansion */
export function expandQuery(query: string): string[] {
  const words = query
    .toLowerCase()
    .replace(/[^\w\s]/g, ' ')
    .split(/\s+/)
    .filter((w) => w.length > 2 && !STOP_WORDS.has(w));

  // Deduplicate preserving order
  return [...new Set(words)];
}

/** Parse code-aware query features for structural retrieval. */
export function parseStructuralQuery(query: string): StructuralQuery {
  const quotedTerms = [...query.matchAll(/"([^"]+)"|'([^']+)'/g)]
    .map((match) => match[1] ?? match[2])
    .filter(Boolean);

  const pathFragments = [
    ...query.matchAll(/(?:[\w.-]+\/)+[\w.-]+(?:\.[A-Za-z0-9]+)?/g),
    ...query.matchAll(/\b[\w.-]+\.(?:ts|tsx|js|jsx|py|rs|go|java)\b/g),
  ]
    .map((match) => match[0])
    .filter((value, index, all) => all.indexOf(value) === index);

  const extensions = [...query.matchAll(/\.(ts|tsx|js|jsx|py|rs|go|java)\b/gi)]
    .map((match) => match[1].toLowerCase())
    .filter((value, index, all) => all.indexOf(value) === index);

  const rawIdentifiers = [
    ...query.matchAll(/\b[A-Za-z_$][A-Za-z0-9_$]*\b/g),
  ]
    .map((match) => match[0])
    .filter((word) => word.length > 1 && !STOP_WORDS.has(word.toLowerCase()));

  for (const quoted of quotedTerms) {
    if (/^[A-Za-z_$][A-Za-z0-9_$]*$/.test(quoted)) rawIdentifiers.push(quoted);
  }

  for (const path of pathFragments) {
    const filename = path.split('/').pop() ?? path;
    const withoutExt = filename.replace(/\.[^.]+$/, '');
    if (withoutExt.length > 1) rawIdentifiers.push(withoutExt);
  }

  const identifiers = [...new Set(rawIdentifiers)];
  const identifierParts = [...new Set(identifiers.flatMap(splitIdentifier))]
    .filter((part) => part.length > 1 && !STOP_WORDS.has(part));
  const normalizedIdentifiers = [...new Set([
    ...identifiers.map(normalizeSymbolName),
    ...identifierParts.map(normalizeSymbolName),
    ...quotedTerms.map(normalizeSymbolName),
  ])].filter(Boolean);

  const pathTokens = [...new Set(pathFragments.flatMap((fragment) =>
    fragment
      .toLowerCase()
      .split(/[/. _-]+/)
      .filter((part) => part.length > 1 && !STOP_WORDS.has(part))
  ))];

  return {
    raw: query,
    tokens: expandQuery(query),
    identifiers,
    normalizedIdentifiers,
    identifierParts,
    pathFragments,
    pathTokens,
    extensions,
    quotedTerms: quotedTerms.map(normalizeIdentifier),
  };
}

/** Estimate query complexity/scope for adaptive budget sizing */
export function estimateComplexity(query: string, expandedTerms: string[]): 'narrow' | 'moderate' | 'broad' {
  const lower = query.toLowerCase();
  const words = lower.split(/\s+/);
  const termCount = expandedTerms.length;

  // Count broadening vs narrowing signals
  let broadSignals = 0;
  let narrowSignals = 0;
  for (const word of words) {
    if (BROADENING_TERMS.has(word)) broadSignals++;
    if (NARROWING_TERMS.has(word)) narrowSignals++;
  }

  // Path-like patterns (src/foo/bar.ts) indicate narrow targeting
  if (/[a-z0-9_.-]+\/[a-z0-9_.-]+/.test(lower) || /\.(ts|tsx|js|jsx|py|rs|go|java)\b/.test(lower)) {
    narrowSignals += 2;
  }

  if (/\b[A-Za-z_$][A-Za-z0-9_$]*\(\)/.test(query) || /\b[A-Za-z]+(?:[A-Z][a-z0-9]+)+\b/.test(query) || /\b[a-z]+_[a-z0-9_]+\b/.test(query)) {
    narrowSignals++;
  }

  // Long queries are common for concrete coding tasks. Treat them as broad
  // only when they also contain explicit broadening language.
  if (termCount >= 8 && broadSignals > 0) broadSignals++;
  if (termCount <= 2) narrowSignals++;

  if (narrowSignals > broadSignals + 1) return 'narrow';
  if (broadSignals > narrowSignals + 1) return 'broad';
  return 'moderate';
}

export type { RetrievalStrategy } from '../types/index.js';

/**
 * Determine the retrieval strategy from the embedding provider.
 *
 * Justified by the contamination-free commit-derived benchmark (django /
 * typescript / rust) under the GPU code model — see
 * `benchmarks/COMMIT-DERIVED-FINDINGS.md` and `benchmarks/FROZEN-CLAIM.md`. The
 * earlier "vector-only beats hybrid by 7.5–19%" claim came from the retired,
 * train-on-test-contaminated self-corpus ablation and does NOT survive on the
 * honest benchmark: vector-only is in fact WORSE than the calibrated hybrid on
 * both recall and top-1 across all three measured languages.
 *
 * - `gpu` (real code embeddings, e.g. `Salesforce/SFR-Embedding-Code-400M_R`):
 *   `structural` — the calibrated hybrid (RRF over a strong vector arm + FTS at
 *   weights 0.20/0.70/0.70, plus the exact-identifier boost). Under GPU it is
 *   competitive with the strongest lexical baselines on R@10 and beats FTS on
 *   top-1 (Hits@1) on django+typescript — though a correct path-aware BM25F is the
 *   top-1 leader on django/rust (no universal winner; see FROZEN-CLAIM.md). It
 *   dominates vector-only on every language measured (django R@10 0.780 vs 0.868,
 *   H@1 0.310 vs 0.400; ts/rust likewise), so the old `gpu → vector` route is
 *   strictly dominated.
 * - `deterministic` (hash-based): `text` — deterministic embeddings are
 *   near-random vectors, so FTS5/BM25 keyword search is far more reliable.
 * - `local` (weaker general ONNX): `hybrid`. NOTE the bge counter-result: a
 *   *stronger general* model does not safely improve top-1 — fusion calibrated to
 *   trust the vector arm regresses Hits@1 — so do not assume "a better local
 *   model helps" without re-calibrating the per-model fusion weights.
 */
export function getAdaptiveStrategy(): RetrievalStrategy {
  const provider = process.env.EMBEDDING_PROVIDER ?? 'local';
  switch (provider) {
    case 'gpu':
      return 'structural';
    case 'deterministic':
      return 'text';
    case 'local':
    default:
      return 'hybrid';
  }
}

/** Compute adaptive budget ratio based on intent + complexity */
function adaptiveBudgetRatio(intent: QueryIntent, complexity: 'narrow' | 'moderate' | 'broad'): number {
  // Base ratios per intent
  const baseRatio: Record<QueryIntent, number> = {
    debug: 0.6,
    implement: 0.4,
    explain: 0.3,
    code_search: 0.35,
    general: 0.5,
  };

  const base = baseRatio[intent];

  // Complexity adjustment:
  // - narrow: reduce budget (fewer, more targeted results needed)
  // - broad: increase budget (wider context needed)
  switch (complexity) {
    case 'narrow': return Math.max(0.15, base * 0.7);
    case 'broad': return Math.min(0.8, base * 1.3);
    default: return base;
  }
}

export function adaptiveTopK(intent: QueryIntent, complexity: 'narrow' | 'moderate' | 'broad'): number {
  if (complexity === 'broad') return 15;
  if (complexity === 'narrow' || intent === 'code_search') return 5;
  return intent === 'debug' || intent === 'implement' || intent === 'explain' ? 10 : 8;
}

/** Create a retrieval plan from a query */
export function planQuery(query: string): QueryPlan {
  const intent = detectIntent(query);
  const expandedTerms = expandQuery(query);
  const complexity = estimateComplexity(query, expandedTerms);
  const structuralQuery = parseStructuralQuery(query);

  // Strategy is adaptive based on the embedding provider — see getAdaptiveStrategy
  // for the honest, commit-derived justification (gpu → calibrated structural
  // hybrid, deterministic → text, local → hybrid).
  const tokenBudgetRatio = adaptiveBudgetRatio(intent, complexity);

  return {
    intent,
    expandedTerms,
    strategy: getAdaptiveStrategy(),
    maxHops: 0,
    tokenBudgetRatio,
    complexity,
    structuralQuery,
    recommendedTopK: adaptiveTopK(intent, complexity),
  };
}

import type { ContextChunk } from '../types/index.js';
import type { RetrievalMode, RetrievalResult } from './retriever.js';

export type RetrievalComplexity = 'narrow' | 'moderate' | 'broad';

export interface RetrievalSelectionPolicy {
  mode: RetrievalMode;
  hardBudget: number;
  targetBudget: number;
  candidateLimit: number;
  minKeep: number;
  scoreThresholdRatio: number;
  /**
   * Absolute fused-score floor, applied together with the relative
   * `scoreThresholdRatio` (a candidate must clear `max(relative, absolute)`).
   * `0` disables it. See {@link ABSOLUTE_SCORE_FLOOR}.
   */
  absoluteScoreFloor: number;
  maxChunksPerPath: number | null;
}

export interface RetrievalSelectionResult {
  ranked: RetrievalResult[];
  policy: RetrievalSelectionPolicy;
  dropped: Array<{ chunkId: string; reason: string }>;
}

const FOCUSED_TARGETS: Record<RetrievalComplexity, number> = {
  narrow: 6_000,
  moderate: 13_000,
  broad: 18_000,
};

const BROAD_TARGETS: Record<RetrievalComplexity, number> = {
  narrow: 16_000,
  moderate: 28_000,
  broad: 40_000,
};

// Reciprocal-rank-fusion constants mirrored from the retriever's fusion
// (retriever.ts: RRF_K = 60; the GPU/CI harness retrieves to depth ~200). They
// are kept as local literals so this policy module stays free of any runtime
// dependency on the retriever — they are documented invariants, not tuning knobs.
const RRF_K = 60;
const RETRIEVAL_TAIL_RANK = 200;

/**
 * Absolute fused-score floor: a fixed tail threshold `1 / (RRF_K + 200)` ≈ 0.0038.
 * Post-RRF fused scores are sums of `weight / (RRF_K + rank)` contributions, so
 * they live on one consistent, corpus-independent scale regardless of strategy.
 *
 * The threshold equals the contribution a *unit-weight* source would make at the
 * deepest retrieved rank (~200). In the strategies where this floor is actually
 * active (focused/broad — exhaustive sets it to 0), the live fusion weights are
 * sub-unit (the `structural` strategy uses vector/fts ≈ 0.7 and structural ≈ 0.2),
 * so in practice the floor trims a candidate that is supported ONLY by a single
 * weak or deep arm:
 *   - a structural-only fuzzy hit (≈ 0.2/61 ≈ 0.0033) — note an *exact* identifier
 *     match is never affected: it carries the large exact-identifier boost,
 *   - or a single 0.7-weight (vector/fts) hit ranked deeper than ~125 (0.7/186 ≈ 0.0038).
 * Any candidate corroborated by two arms, or holding a strong single-arm rank,
 * sits well above the floor.
 *
 * The relative `scoreThresholdRatio` alone cannot catch weak tails when the whole
 * result set is weak (`threshold = tiny topScore × ratio` is itself tiny), so
 * retrieval would otherwise always return topK even when nothing is relevant.
 * Because the floor is taken as `max(relative, absolute)` it is a no-op whenever a
 * strong result exists (the relative threshold dominates) and only bites on an
 * all-weak set — and even then `minKeep` and the keep-at-least-one fallback below
 * protect the head, so retrieval never returns empty for a non-empty input.
 */
const ABSOLUTE_SCORE_FLOOR = 1 / (RRF_K + RETRIEVAL_TAIL_RANK);

export function createRetrievalSelectionPolicy(options: {
  mode?: RetrievalMode;
  complexity: RetrievalComplexity;
  hardBudget: number;
  requestedTopK: number;
  returnLimit?: number;
}): RetrievalSelectionPolicy {
  const mode = options.mode ?? 'focused';
  const candidateLimit = options.returnLimit ?? options.requestedTopK;

  if (mode === 'exhaustive') {
    return {
      mode,
      hardBudget: options.hardBudget,
      targetBudget: options.hardBudget,
      candidateLimit,
      minKeep: 0,
      scoreThresholdRatio: 0,
      // Exhaustive returns everything up to the hard budget — no floor.
      absoluteScoreFloor: 0,
      maxChunksPerPath: null,
    };
  }

  if (mode === 'broad') {
    return {
      mode,
      hardBudget: options.hardBudget,
      targetBudget: Math.min(options.hardBudget, BROAD_TARGETS[options.complexity]),
      candidateLimit,
      minKeep: 5,
      scoreThresholdRatio: 0.2,
      absoluteScoreFloor: ABSOLUTE_SCORE_FLOOR,
      maxChunksPerPath: 3,
    };
  }

  return {
    mode: 'focused',
    hardBudget: options.hardBudget,
    targetBudget: Math.min(options.hardBudget, FOCUSED_TARGETS[options.complexity]),
    candidateLimit,
    minKeep: 3,
    scoreThresholdRatio: 0.35,
    absoluteScoreFloor: ABSOLUTE_SCORE_FLOOR,
    maxChunksPerPath: 2,
  };
}

export function selectRetrievalCandidates(
  retrieval: RetrievalResult[],
  chunks: Map<string, ContextChunk>,
  policy: RetrievalSelectionPolicy
): RetrievalSelectionResult {
  const selected: RetrievalResult[] = [];
  const dropped: RetrievalSelectionResult['dropped'] = [];
  const pathCounts = new Map<string, number>();
  const candidates: RetrievalResult[] = [];

  for (const result of retrieval) {
    const chunk = chunks.get(result.chunkId);
    if (!chunk) {
      dropped.push({ chunkId: result.chunkId, reason: 'chunk not found' });
      continue;
    }
    if (chunk.metadata?.split) {
      dropped.push({ chunkId: result.chunkId, reason: 'split parent metadata chunk' });
      continue;
    }
    candidates.push(result);
  }

  const topScore = candidates[0]?.score ?? 0;
  const relativeThreshold = topScore * policy.scoreThresholdRatio;
  // Fail safe: a hand-built / Partial policy without absoluteScoreFloor must
  // behave as floor-off, not NaN (which would silently disable ALL trimming via
  // Math.max(x, NaN) === NaN).
  const absoluteFloor = Number.isFinite(policy.absoluteScoreFloor) ? policy.absoluteScoreFloor : 0;
  // A candidate must clear BOTH the relative threshold (proportional to the top
  // hit) and the absolute floor (a fixed minimum fused score). Taking the max
  // means the absolute floor only bites when the relative threshold is too weak
  // to — i.e. when the whole result set is weak — so a strong query is unaffected.
  const effectiveThreshold = Math.max(relativeThreshold, absoluteFloor);

  for (let index = 0; index < candidates.length; index++) {
    if (selected.length >= policy.candidateLimit) {
      dropped.push({ chunkId: candidates[index].chunkId, reason: 'after candidate limit' });
      continue;
    }

    const result = candidates[index];
    const chunk = chunks.get(result.chunkId);
    if (!chunk) continue;
    const isProtected = index < policy.minKeep;

    if (!isProtected && effectiveThreshold > 0 && result.score < effectiveThreshold) {
      const reason = result.score < absoluteFloor
        ? 'below absolute relevance floor'
        : `below ${policy.mode} score threshold`;
      dropped.push({ chunkId: result.chunkId, reason });
      continue;
    }

    const pathKey = chunk.path ?? chunk.source ?? chunk.id;
    const currentPathCount = pathCounts.get(pathKey) ?? 0;
    if (
      !isProtected &&
      policy.maxChunksPerPath !== null &&
      currentPathCount >= policy.maxChunksPerPath
    ) {
      dropped.push({ chunkId: result.chunkId, reason: 'per-path candidate cap' });
      continue;
    }

    selected.push(result);
    pathCounts.set(pathKey, currentPathCount + 1);
  }

  if (selected.length === 0 && candidates[0]) {
    selected.push(candidates[0]);
  }

  return { ranked: selected, policy, dropped };
}

export function budgetForSelectedCandidates(
  selected: RetrievalResult[],
  chunks: Map<string, ContextChunk>,
  policy: RetrievalSelectionPolicy
): number {
  if (policy.mode === 'exhaustive') return policy.hardBudget;

  let protectedTokens = 0;
  for (const result of selected.slice(0, policy.minKeep)) {
    protectedTokens += chunks.get(result.chunkId)?.tokensEstimate ?? 0;
  }

  return Math.min(policy.hardBudget, Math.max(policy.targetBudget, protectedTokens));
}

import type {
  CodeReference,
  CodeSymbol,
  ContextChunk,
  EmbeddingProvider,
  EmbeddingQuality,
  RerankerProvider,
  RetrievalMode,
  RetrievalStrategy,
  StructuralQuery,
  StructuralSearchResult,
} from '../types/index.js';
import type { SQLiteRepository } from '../storage/repository.js';
import { parseStructuralQuery } from './query-planner.js';
import { normalizeSymbolName, splitIdentifier } from '../providers/structural-indexer.js';

export type { RetrievalMode } from '../types/index.js';

export interface RetrievalResult {
  chunkId: string;
  score: number;
  sources: RetrievalSource[];
  sourceScores?: {
    structural: number;
    vector: number;
    fts: number;
    graph: number;
    dependency: number;
    final: number;
  };
  reasons: string[];
}

export type RetrievalSource = 'structural' | 'vector' | 'fts' | 'graph' | 'dependency';
export type RetrievalSourceScores = NonNullable<RetrievalResult['sourceScores']>;

export interface RetrievalOptions {
  topK?: number;
  returnLimit?: number;
  maxHops?: number;
  strategy?: RetrievalStrategy;
  mode?: RetrievalMode;
}

const SOURCE_SCORE_FIELDS: Array<keyof RetrievalSourceScores> = [
  'structural',
  'vector',
  'fts',
  'graph',
  'dependency',
  'final',
];

export function formatSourceScoreBreakdown(sourceScores: RetrievalSourceScores): string {
  return `scores ${SOURCE_SCORE_FIELDS
    .map((field) => `${field}=${sourceScores[field].toFixed(3)}`)
    .join(' ')}`;
}

/** Maximum candidates to send to the reranker (avoids unnecessary work) */
const RERANKER_MAX_CANDIDATES = 20;

/**
 * Single source of truth for embedding quality. Prefers the provider's declared
 * `quality` tier; falls back to a constructor-name check for older providers and
 * test mocks. Replaces the brittle `constructor.name` check that broke under
 * minification and disagreed with the env-var path in the query planner.
 */
function inferEmbeddingQuality(provider: EmbeddingProvider): EmbeddingQuality {
  if (provider.quality) return provider.quality;
  return provider.constructor?.name === 'DeterministicEmbeddingProvider'
    ? 'deterministic'
    : 'local';
}

export class HybridRetriever {
  private reranker: RerankerProvider | null;
  private vectorReliable: boolean;

  constructor(
    private storage: SQLiteRepository,
    private embeddingProvider: EmbeddingProvider,
    reranker?: RerankerProvider
  ) {
    this.reranker = reranker ?? null;
    this.vectorReliable = inferEmbeddingQuality(embeddingProvider) !== 'deterministic';
  }

  async retrieve(query: string, options: RetrievalOptions = {}): Promise<RetrievalResult[]> {
    const { topK = 50, strategy = 'hybrid' } = options;
    const maxHops = options.maxHops ?? (strategy === 'graph' ? 1 : 0);
    const fused = new Map<string, FusedCandidate>();
    const structuralQuery = parseStructuralQuery(query);
    const strongIdentifiers = buildStrongIdentifierSet(query, structuralQuery);
    const useStructural = strategy === 'structural';
    const useVector = strategy === 'hybrid' || strategy === 'vector' || strategy === 'structural';
    const useFts = strategy === 'hybrid' || strategy === 'text' || strategy === 'structural';
    const useGraph = strategy === 'graph' || ((strategy === 'hybrid') && maxHops > 0);
    const fallbackSourcesAvailable = useStructural || useFts;
    const retrievalWarnings: string[] = [];

    if (strategy === 'structural' && !this.vectorReliable) {
      return this.retrieveDeterministicStructural(query, topK);
    }

    const weights = getFusionWeights(strategy, this.vectorReliable);

    // Structural symbol/path/reference search
    if (useStructural) {
      try {
        const structuralResults = this.storage.searchByStructure(structuralQuery, Math.max(topK, 50));
        addSource(
          fused,
          'structural',
          structuralResults.map((result) => ({
            chunkId: result.chunkId,
            score: result.structuralScore,
            reasons: result.reasons,
          })),
          weights.structural
        );
        addSource(
          fused,
          'dependency',
          structuralResults
            .filter((result) => result.dependencyBoost > 0)
            .map((result) => ({
              chunkId: result.chunkId,
              score: result.dependencyBoost,
              reasons: result.reasons.filter((reason) => reason.includes('reference')),
            })),
          weights.dependency
        );
        applyStrongIdentifierStructuralBoost(fused, structuralResults, strongIdentifiers);
      } catch (err) {
        if (!useVector && !useFts) throw err;
        retrievalWarnings.push(`structural retrieval unavailable: ${errorMessage(err)}`);
      }
    }

    // Vector search
    if (useVector) {
      try {
        const queryEmbedding = await this.embeddingProvider.embed(query);
        if (queryEmbedding.length > 0) {
          const vectorResults = this.storage.searchByVector(queryEmbedding, Math.max(topK, 50));
          addSource(
            fused,
            'vector',
            vectorResults.map((result) => ({ ...result, reasons: ['vector similarity match'] })),
            weights.vector
          );
        }
      } catch (err) {
        if (!fallbackSourcesAvailable) throw err;
        retrievalWarnings.push(`vector retrieval unavailable: ${errorMessage(err)}`);
      }
    }

    // Full-text search
    if (useFts) {
      const textResults = searchTextSources(this.storage, query, Math.max(topK, 50), retrievalWarnings);
      if (textResults.failures > 0 && textResults.successes === 0 && !useStructural && !useVector) {
        throw textResults.firstError ?? new Error('text retrieval unavailable');
      }
      addSource(
        fused,
        'fts',
        textResults.results.map((result) => ({ ...result, reasons: ['keyword match (FTS5/BM25)'] })),
        weights.fts
      );
    }

    // Graph traversal from seed results
    if (useGraph && maxHops > 0 && fused.size > 0) {
      const seedIds = [...fused.entries()]
        .sort((a, b) => b[1].fusedScore - a[1].fusedScore)
        .slice(0, 10)
        .map(([chunkId]) => chunkId);
      try {
        const expanded = this.multiHopExpand(seedIds, maxHops, topK);
        addSource(
          fused,
          'graph',
          expanded.map((result) => ({ ...result, reasons: ['dependency graph traversal'] })),
          weights.graph
        );
      } catch (err) {
        if (strategy === 'graph') throw err;
        retrievalWarnings.push(`graph retrieval unavailable: ${errorMessage(err)}`);
      }
    }

    // Pure graph strategy without seeds — use all chunks
    if (strategy === 'graph' && maxHops > 0 && fused.size === 0) {
      const allChunks = this.storage.getAllChunks();
      if (allChunks.length > 0) {
        // For pure graph, start from recently routed chunks
        const recentChunks = allChunks.slice(-10);
        const expanded = this.multiHopExpand(
          recentChunks.map((c) => c.id),
          maxHops,
          topK
        );
        addSource(
          fused,
          'graph',
          expanded.map((result) => ({ ...result, reasons: ['dependency graph traversal'] })),
          weights.graph || 1
        );
      }
    }

    if (fused.size === 0) return [];

    // Sort by fused score and return
    const sorted = [...fused.entries()]
      .sort((a, b) => b[1].fusedScore - a[1].fusedScore)
      .slice(0, topK);

    // Rerank top candidates by keyword overlap if a reranker is available
    let reranked = sorted;
    if (this.reranker && sorted.length > 0) {
      const candidates = sorted.slice(0, RERANKER_MAX_CANDIDATES);
      const documents = candidates.map(([chunkId]) => {
        const chunk = this.storage.getChunk(chunkId);
        return chunk ? `${chunk.path ?? ''}\n${chunk.text}` : '';
      });

      try {
        const rerankResults = await this.reranker.rerank(query, documents);

        // Build a reranker score lookup and re-sort candidates
        const rerankScoreMap = new Map<number, { score: number; reason: string }>();
        for (const r of rerankResults) {
          if (Number.isFinite(r.index) && Number.isFinite(r.score)) {
            rerankScoreMap.set(r.index, { score: r.score, reason: r.reason });
          }
        }

        // Re-sort candidates by combined score (fused + small reranker boost)
        const rerankedCandidates = candidates.map(([chunkId, data], idx) => {
          const rerank = rerankScoreMap.get(idx);
          const rerankerScore = rerank?.score ?? 0;
          // Both boosts are rescaled to the RRF magnitude (data.fusedScore is a
          // sum of weight/(RRF_K+rank) terms, typically O(0.0x)). The reranker
          // score is normally in [0,1]; multiplying by ~3 top-rank contributions
          // lets a confident reranker move a chunk a few ranks. An exact
          // structural match adds ~2 top-rank contributions on top.
          // Typed exact-match flag (uncapped) replaces reason-string prefix matching,
          // so the exact-identifier boost survives a structural-indexer reason reword
          // or the 6/8-entry reason cap.
          const exactStructuralBoost = (data.symbolExact || data.pathExact)
            ? RRF_TOP_CONTRIBUTION * 2 : 0;
          const rerankReasons = [];
          if (rerank) rerankReasons.push(`reranker ${rerank.reason}: ${rerankerScore.toFixed(3)}`);
          if (exactStructuralBoost > 0) {
            rerankReasons.push(`rerank exact structural boost: ${exactStructuralBoost.toFixed(3)}`);
          }
          return {
            chunkId,
            data,
            combinedScore: data.fusedScore + exactStructuralBoost + rerankerScore * RRF_TOP_CONTRIBUTION * 3,
            rerankReasons,
          };
        });
        rerankedCandidates.sort((a, b) => b.combinedScore - a.combinedScore);

        reranked = [
          ...rerankedCandidates.map(({ chunkId, data, combinedScore, rerankReasons }) => {
            data.finalScore = combinedScore;
            data.rerankReasons = rerankReasons;
            return [chunkId, data] as [string, typeof data];
          }),
          ...sorted.slice(candidates.length),
        ];
      } catch {
        // Reranker failure is non-fatal — fall back to RRF ordering
      }
    }

    // Build result objects with reasons
    return reranked.map(([chunkId, data]) => {
      const reasons: string[] = [];
      const sources = [...data.sources] as RetrievalSource[];

      reasons.push(...data.reasons);
      reasons.push(...(data.rerankReasons ?? []));
      reasons.push(...retrievalWarnings);
      if (data.sources.has('dependency') && !data.reasons.some((reason) => reason.includes('reference'))) {
        reasons.push('direct dependency/reference boost');
      }

      const sourceScores = buildSourceScores(data);
      reasons.push(formatSourceScoreBreakdown(sourceScores));

      return { chunkId, score: sourceScores.final, sources, sourceScores, reasons };
    });
  }

  private multiHopExpand(
    seedIds: string[],
    maxHops: number,
    maxChunks: number
  ): { chunkId: string; score: number }[] {
    const visited = new Set<string>(seedIds);
    let frontier = seedIds;
    const results: { chunkId: string; score: number }[] = [];

    for (let hop = 0; hop < maxHops; hop++) {
      const nextFrontier: string[] = [];
      for (const id of frontier) {
        const deps = this.storage.getDependencies(id);
        for (const dep of deps) {
          const other = dep.fromId === id ? dep.toId : dep.fromId;
          if (!visited.has(other) && results.length + nextFrontier.length < maxChunks) {
            nextFrontier.push(other);
            visited.add(other);
            results.push({ chunkId: other, score: 1 / (hop + 1) });
          }
        }
      }
      frontier = nextFrontier;
      if (frontier.length === 0) break;
    }

    return results;
  }

  private retrieveDeterministicStructural(query: string, topK: number): RetrievalResult[] {
    const structuralQuery = parseStructuralQuery(query);
    const retrievalWarnings: string[] = [];
    const strongIdentifiers = buildStrongIdentifierSet(query, structuralQuery);
    const strongIdentifierCases = buildStrongIdentifierCaseSet(query, structuralQuery);
    let lexicalResults: { chunkId: string; score: number }[] = [];
    try {
      lexicalResults = typeof this.storage.searchByLexical === 'function'
        ? this.storage.searchByLexical(query, Math.max(topK, 50))
        : this.storage.searchByText(query, Math.max(topK, 50));
    } catch (err) {
      pushUniqueWarning(retrievalWarnings, `text retrieval unavailable: ${errorMessage(err)}`);
    }

    let structuralResults: StructuralSearchResult[] = [];
    try {
      structuralResults = this.storage.searchByStructure(structuralQuery, Math.max(topK, 50));
    } catch (err) {
      pushUniqueWarning(retrievalWarnings, `structural retrieval unavailable: ${errorMessage(err)}`);
    }
    const structuralData = createStructuralDataCache(this.storage, retrievalWarnings);
    const corpusStemIndex = buildCorpusStemIndex(structuralData.allSymbols());
    const sparseTerms = buildSparseStructuralTerms(structuralQuery, corpusStemIndex);
    const pathIntentTerms = buildPathIntentTerms(sparseTerms);
    const candidates = new Map<string, FusedCandidate>();
    const shouldScoreSparseFields = sparseTerms.length > 0 || strongIdentifiers.size > 0;

    for (const result of lexicalResults) {
      const lexicalScore = scaleDeterministicLexicalScore(result.score);
      if (lexicalScore <= 0) continue;
      candidates.set(result.chunkId, {
        fusedScore: lexicalScore,
        sources: new Set<RetrievalSource>(['fts']),
        sourceScores: { fts: lexicalScore },
        reasons: ['lexical keyword/path match'],
      });
    }

    for (const result of structuralResults) {
      const exactIdentifier = result.reasons.some((reason) =>
        isExactIdentifierSeedReason(reason, strongIdentifiers)
      );
      const exactPath = structuralQuery.pathFragments.length > 0 && !!result.pathExact;
      const boost = exactIdentifier
        ? 12 + result.structuralScore
        : exactPath
          ? 10 + result.structuralScore
          : 0;
      if (boost <= 0) continue;
      const existing = candidates.get(result.chunkId) ?? {
        fusedScore: 0,
        sources: new Set<RetrievalSource>(),
        sourceScores: {},
        reasons: [],
      };
      existing.fusedScore += boost;
      existing.sources.add('structural');
      existing.sourceScores.structural = (existing.sourceScores.structural ?? 0) + boost;
      // Propagate the typed exact-match flags (uncapped) into the fused candidate.
      if (result.symbolExact) existing.symbolExact = true;
      if (result.pathExact) existing.pathExact = true;
      for (const reason of result.reasons) {
        if (!existing.reasons.includes(reason) && existing.reasons.length < 8) existing.reasons.push(reason);
      }
      candidates.set(result.chunkId, existing);
    }

    if (shouldScoreSparseFields || structuralQuery.tokens.length > 0 || structuralQuery.identifierParts.length > 0) {
      for (const chunk of this.storage.getAllChunks()) {
        if (chunk.metadata?.split) continue;
        const symbols = shouldScoreSparseFields ? structuralData.symbolsFor(chunk.id) : [];
        const references = shouldScoreSparseFields ? structuralData.referencesFor(chunk.id) : [];
        const sparseScore = shouldScoreSparseFields ? scoreSparseStructuralFields(
          chunk,
          sparseTerms,
          symbols,
          references,
          strongIdentifiers,
          strongIdentifierCases
        ) : { score: 0, reasons: [] };
        const pathIntent = scorePathIntent(chunk, structuralQuery, pathIntentTerms);
        const combinedScore = sparseScore.score + pathIntent.score;
        if (combinedScore <= 0) continue;
        const existing = candidates.get(chunk.id) ?? {
          fusedScore: 0,
          sources: new Set<RetrievalSource>(),
          sourceScores: {},
          reasons: [],
        };
        existing.fusedScore += combinedScore;
        existing.sources.add('structural');
        existing.sourceScores.structural = (existing.sourceScores.structural ?? 0) + combinedScore;
        for (const reason of [...pathIntent.reasons, ...sparseScore.reasons]) {
          if (!existing.reasons.includes(reason) && existing.reasons.length < 8) existing.reasons.push(reason);
        }
        candidates.set(chunk.id, existing);
      }
    }

    return [...candidates.entries()]
      .sort((a, b) => b[1].fusedScore - a[1].fusedScore)
      .slice(0, topK)
      .map(([chunkId, data]) => {
        const sourceScores = buildSourceScores(data);
        return {
          chunkId,
          score: sourceScores.final,
          sources: [...data.sources],
          sourceScores,
          reasons: [
            ...data.reasons,
            ...retrievalWarnings,
            formatSourceScoreBreakdown(sourceScores),
          ],
        };
      });
  }
}

interface StructuralDataCache {
  symbolsFor(chunkId: string): CodeSymbol[];
  referencesFor(chunkId: string): CodeReference[];
  allSymbols(): CodeSymbol[];
}

function createStructuralDataCache(
  storage: SQLiteRepository,
  warnings: string[]
): StructuralDataCache {
  const symbolCache = new Map<string, CodeSymbol[]>();
  const referenceCache = new Map<string, CodeReference[]>();
  let allSymbolsList: CodeSymbol[] = [];
  let symbolsBatched = false;
  let referencesBatched = false;
  let symbolBatchAttempted = false;
  let referenceBatchAttempted = false;
  let symbolLookupFailed = false;
  let referenceLookupFailed = false;

  const loadSymbolsBatch = () => {
    if (symbolBatchAttempted) return;
    symbolBatchAttempted = true;
    try {
      const symbols = typeof storage.getAllCodeSymbols === 'function'
        ? storage.getAllCodeSymbols()
        : null;
      if (symbols) {
        allSymbolsList = symbols;
        fillStructuralCache(symbolCache, symbols, (symbol) => symbol.chunkId);
        symbolsBatched = true;
      }
    } catch {
      symbolsBatched = false;
    }
  };

  const loadReferencesBatch = () => {
    if (referenceBatchAttempted) return;
    referenceBatchAttempted = true;
    try {
      const references = typeof storage.getAllCodeReferences === 'function'
        ? storage.getAllCodeReferences()
        : null;
      if (references) {
        fillStructuralCache(referenceCache, references, (reference) => reference.chunkId);
        referencesBatched = true;
      }
    } catch {
      referencesBatched = false;
    }
  };

  return {
    symbolsFor(chunkId: string): CodeSymbol[] {
      loadSymbolsBatch();
      if (symbolsBatched) return symbolCache.get(chunkId) ?? [];
      if (symbolCache.has(chunkId)) return symbolCache.get(chunkId) ?? [];
      if (symbolLookupFailed) return [];
      const symbols = safeCodeSymbols(storage, chunkId, warnings);
      symbolCache.set(chunkId, symbols);
      if (symbols.length === 0 && warnings.some((warning) => warning.startsWith('code symbol lookup unavailable'))) {
        symbolLookupFailed = true;
      }
      return symbols;
    },
    referencesFor(chunkId: string): CodeReference[] {
      loadReferencesBatch();
      if (referencesBatched) return referenceCache.get(chunkId) ?? [];
      if (referenceCache.has(chunkId)) return referenceCache.get(chunkId) ?? [];
      if (referenceLookupFailed) return [];
      const references = safeCodeReferences(storage, chunkId, warnings);
      referenceCache.set(chunkId, references);
      if (references.length === 0 && warnings.some((warning) => warning.startsWith('code reference lookup unavailable'))) {
        referenceLookupFailed = true;
      }
      return references;
    },
    allSymbols(): CodeSymbol[] {
      loadSymbolsBatch();
      return allSymbolsList;
    },
  };
}

function fillStructuralCache<T>(
  cache: Map<string, T[]>,
  items: T[],
  getChunkId: (item: T) => string | undefined
): void {
  for (const item of items) {
    const chunkId = getChunkId(item);
    if (!chunkId) continue;
    const existing = cache.get(chunkId);
    if (existing) {
      existing.push(item);
    } else {
      cache.set(chunkId, [item]);
    }
  }
}

function buildSourceScores(data: FusedCandidate): RetrievalSourceScores {
  return {
    structural: data.sourceScores.structural ?? 0,
    vector: data.sourceScores.vector ?? 0,
    fts: data.sourceScores.fts ?? 0,
    graph: data.sourceScores.graph ?? 0,
    dependency: data.sourceScores.dependency ?? 0,
    final: data.finalScore ?? data.fusedScore,
  };
}

function errorMessage(err: unknown): string {
  return err instanceof Error ? err.message : String(err);
}

function pushUniqueWarning(warnings: string[], warning: string): void {
  if (!warnings.includes(warning)) warnings.push(warning);
}

function safeCodeSymbols(
  storage: SQLiteRepository,
  chunkId: string,
  warnings: string[]
): CodeSymbol[] {
  try {
    return storage.getCodeSymbols(chunkId);
  } catch (err) {
    pushUniqueWarning(warnings, `code symbol lookup unavailable: ${errorMessage(err)}`);
    return [];
  }
}

function safeCodeReferences(
  storage: SQLiteRepository,
  chunkId: string,
  warnings: string[]
): CodeReference[] {
  try {
    return storage.getCodeReferences(chunkId);
  } catch (err) {
    pushUniqueWarning(warnings, `code reference lookup unavailable: ${errorMessage(err)}`);
    return [];
  }
}

function searchTextSources(
  storage: SQLiteRepository,
  query: string,
  topK: number,
  warnings: string[]
): {
  results: { chunkId: string; score: number }[];
  successes: number;
  failures: number;
  firstError?: unknown;
} {
  const resultSets: Array<{ chunkId: string; score: number }[]> = [];
  let successes = 0;
  let failures = 0;
  let firstError: unknown;

  const run = (source: 'full-text' | 'lexical', search: () => { chunkId: string; score: number }[]) => {
    try {
      resultSets.push(search());
      successes++;
    } catch (err) {
      failures++;
      firstError ??= err;
      pushUniqueWarning(warnings, `${source} retrieval unavailable: ${errorMessage(err)}`);
    }
  };

  run('full-text', () => storage.searchByText(query, topK));
  if (typeof storage.searchByLexical === 'function') {
    run('lexical', () => storage.searchByLexical(query, topK));
  }

  return {
    results: mergeRawResults(resultSets),
    successes,
    failures,
    firstError,
  };
}

interface SourceResult {
  chunkId: string;
  score: number;
  reasons: string[];
}

interface FusedCandidate {
  fusedScore: number;
  finalScore?: number;
  sources: Set<RetrievalSource>;
  sourceScores: Partial<Record<RetrievalSource, number>>;
  reasons: string[];
  rerankReasons?: string[];
  symbolExact?: boolean;
  pathExact?: boolean;
}

const STRONG_IDENTIFIER_STOP_WORDS = new Set([
  'contain',
  'contains',
  'defined',
  'definition',
  'file',
  'files',
  'find',
  'grep',
  'locate',
  'show',
  'where',
  'which',
]);

function buildStrongIdentifierSet(query: string, structuralQuery: StructuralQuery): Set<string> {
  return new Set(
    buildStrongIdentifierCandidates(query, structuralQuery)
      .map((identifier) => normalizeStrongIdentifier(identifier))
      .filter((identifier) => identifier.length > 0)
  );
}

function buildStrongIdentifierCaseSet(query: string, structuralQuery: StructuralQuery): Set<string> {
  return new Set(buildStrongIdentifierCandidates(query, structuralQuery));
}

function buildStrongIdentifierCandidates(query: string, structuralQuery: StructuralQuery): string[] {
  const lowercaseExactCue = /\b(find|where|locate|show|contains|defined|grep|which\s+file)\b/i.test(query);
  const explainSymbolCue = /\b(?:what\s+does|what\s+do|explain|describe|implementation|how\s+does|how\s+do)\b/i.test(query);
  const behaviorSubjectIdentifiers = new Set(
    [...query.matchAll(/\b([A-Za-z_$][A-Za-z0-9_$]*)\s+(?:is|are)\s+(?:returning|giving|producing)\s+(?:wrong|bad|incorrect|unexpected)\s+values?\b/gi)]
      .map((match) => match[1])
  );

  return structuralQuery.identifiers
    .filter((identifier) => !STRONG_IDENTIFIER_STOP_WORDS.has(identifier.toLowerCase()))
    .filter((identifier) =>
      /[a-z0-9][A-Z]/.test(identifier) ||
      identifier.includes('_') ||
      /^[A-Z]{2,}$/.test(identifier) ||
      /^[A-Z][a-z0-9]+[A-Z][A-Za-z0-9]*$/.test(identifier) ||
      (explainSymbolCue && /^[A-Z][A-Za-z0-9_$]{2,}$/.test(identifier)) ||
      (behaviorSubjectIdentifiers.has(identifier) && /^[a-z][a-z0-9_$]{2,}$/.test(identifier)) ||
      (lowercaseExactCue && /^[a-z][a-z0-9_$]{4,}$/.test(identifier)) ||
      (lowercaseExactCue && /[A-Z]/.test(identifier) && /^[A-Za-z][A-Za-z0-9_$]{4,}$/.test(identifier))
    );
}

function applyStrongIdentifierStructuralBoost(
  fused: Map<string, FusedCandidate>,
  structuralResults: StructuralSearchResult[],
  strongIdentifiers: Set<string>
): void {
  if (strongIdentifiers.size === 0 || structuralResults.length === 0) return;

  for (const result of structuralResults) {
    const symbolMatches = new Set<string>();
    const referenceMatches = new Set<string>();
    for (const reason of result.reasons) {
      const symbol = extractReasonValueFromPrefixes(reason, [
        'symbol exact match: ',
        'symbol strong exact match: ',
      ]);
      if (symbol && strongIdentifiers.has(normalizeStrongIdentifier(symbol))) {
        symbolMatches.add(symbol);
      }
      const reference = extractReasonValueFromPrefixes(reason, [
        'direct reference exact match: ',
        'direct reference strong exact match: ',
      ]);
      if (reference && strongIdentifiers.has(normalizeStrongIdentifier(reference))) {
        referenceMatches.add(reference);
      }
    }

    const candidate = fused.get(result.chunkId);
    if (!candidate) continue;

    // Rescaled to the RRF magnitude. The previous raw values (~1.25) were on the
    // old min-max scale and would dwarf RRF contributions (~0.016 at rank 1). An
    // exact symbol match is now worth ~3 top-rank RRF contributions plus a small
    // per-match increment; a direct reference match adds ~1 top-rank contribution.
    // This meaningfully promotes exact matches without overwhelming the agreement
    // signal of several sources independently ranking a chunk highly.
    const symbolBoost = symbolMatches.size > 0
      ? RRF_TOP_CONTRIBUTION * (3 + Math.min(1, symbolMatches.size * 0.3))
      : 0;
    const referenceBoost = referenceMatches.size > 0 ? RRF_TOP_CONTRIBUTION * 1 : 0;
    const exactIdentifierBoost = symbolBoost + referenceBoost;
    if (exactIdentifierBoost <= 0) continue;

    candidate.fusedScore += exactIdentifierBoost;
    candidate.sources.add('structural');
    candidate.sourceScores.structural = (candidate.sourceScores.structural ?? 0) + exactIdentifierBoost;
    if (candidate.reasons.length < 8) {
      const matched = [
        ...[...symbolMatches].map((name) => `symbol:${name}`),
        ...[...referenceMatches].map((name) => `reference:${name}`),
      ].slice(0, 2);
      candidate.reasons.push(`exact identifier boost: ${matched.join(', ')}`);
    }
  }
}

function extractReasonValue(reason: string, prefix: string): string | null {
  if (!reason.startsWith(prefix)) return null;
  const value = reason.slice(prefix.length).trim();
  return value.length > 0 ? value : null;
}

function extractReasonValueFromPrefixes(reason: string, prefixes: string[]): string | null {
  for (const prefix of prefixes) {
    const value = extractReasonValue(reason, prefix);
    if (value) return value;
  }
  return null;
}

function isExactIdentifierSeedReason(reason: string, strongIdentifiers: Set<string>): boolean {
  if (strongIdentifiers.size === 0) return false;
  const value = extractReasonValueFromPrefixes(reason, [
    'symbol exact match: ',
    'direct reference exact match: ',
  ]);
  return value !== null && strongIdentifiers.has(normalizeStrongIdentifier(value));
}

function normalizeStrongIdentifier(identifier: string): string {
  return identifier.toLowerCase().replace(/[^a-z0-9_$]/g, '');
}

/**
 * Benchmark-only fusion calibration hooks. Both are null in production, so the
 * hot path is unchanged; they exist so the WS0.3 fusion-sweep harness
 * (`benchmarks/fusion-sweep.ts`) can vary the fusion weights and the vector
 * relevance floor in-process — without re-embedding the corpus per config.
 * Keyed by `${strategy}:${vectorReliable ? 'reliable' : 'deterministic'}`.
 */
let fusionWeightsOverride: Map<string, Record<RetrievalSource, number>> | null = null;
let vectorFloorOverride: number | null = null;

export function setFusionWeightsOverride(
  override: Record<string, Record<RetrievalSource, number>> | null
): void {
  fusionWeightsOverride = override ? new Map(Object.entries(override)) : null;
}

export function setVectorFloorOverride(floor: number | null): void {
  vectorFloorOverride = floor;
}

function getFusionWeights(strategy: RetrievalStrategy, vectorReliable: boolean): Record<RetrievalSource, number> {
  if (fusionWeightsOverride) {
    const override = fusionWeightsOverride.get(`${strategy}:${vectorReliable ? 'reliable' : 'deterministic'}`);
    if (override) return override;
  }
  if (strategy === 'structural') {
    // WS0.3 fusion calibration (commit-derived GPU sweep, benchmarks/fusion-sweep.ts).
    // When the vector arm is a real code-embedding model the previous
    // structural-heavy weights (0.58/0.24/0.15) UNDER-used the now-strong vector
    // signal and the fused result fell BELOW max(vector, fts). Trusting vector and
    // fts equally and highly — with the structural arm demoted to a light booster
    // (the exact-identifier boost still fires regardless of this weight) — fixes
    // that: on django (vector≈fts) fused R@10 0.733→~0.87 (now > fts), on
    // typescript (fts-dominant, weaker vector) 0.581→~0.69 (≈ fts, no longer below
    // the broken default). Selected as the robust cross-repo config on a
    // calibration split, holdout-validated. See benchmarks/COMMIT-DERIVED-FINDINGS.md.
    return vectorReliable
      ? { structural: 0.2, vector: 0.7, fts: 0.7, dependency: 0.03, graph: 0 }
      : { structural: 0.09, vector: 0, fts: 0.88, dependency: 0.03, graph: 0 };
  }
  if (strategy === 'vector') {
    return { structural: 0, vector: 1, fts: 0, dependency: 0, graph: 0 };
  }
  if (strategy === 'text') {
    return { structural: 0, vector: 0, fts: 1, dependency: 0, graph: 0 };
  }
  if (strategy === 'graph') {
    return { structural: 0, vector: 0, fts: 0, dependency: 0, graph: 1 };
  }
  return { structural: 0, vector: 0.55, fts: 0.4, dependency: 0, graph: 0.05 };
}

/**
 * Reciprocal Rank Fusion constant. A chunk at 1-based rank `r` in a source
 * contributes `weight / (RRF_K + r)`. k=60 is the canonical default from
 * Cormack et al. (2009); it dampens the gap between top ranks without letting
 * any single source dominate.
 */
const RRF_K = 60;

/** Top-rank (rank 1) RRF contribution at unit weight: 1 / (RRF_K + 1). */
const RRF_TOP_CONTRIBUTION = 1 / (RRF_K + 1);

/**
 * Absolute relevance floor for vector (cosine) results. Cosine similarities
 * below this are treated as noise and dropped before ranking, so a source with
 * no genuinely-relevant hit contributes nothing and retrieval can return [].
 */
const VECTOR_RELEVANCE_FLOOR = 0.2;

/**
 * Reciprocal Rank Fusion. Replaces the previous weighted min-max sum, which was
 * not scale-free: a source whose raw scores happened to span a wider range
 * dominated regardless of agreement. RRF is rank-based — only the order of each
 * source's results matters — so heterogeneous score scales (cosine ~0..1, BM25
 * negative log-odds, structural integers) become commensurate.
 *
 * For each source the results are sorted by score descending; the chunk at
 * 1-based rank `r` contributes `weight / (RRF_K + r)` to its fused score, and
 * contributions accumulate across sources. The per-source breakdown in
 * `sourceScores[source]` stores that RRF contribution (not the raw score).
 *
 * An absolute relevance floor is applied per source BEFORE ranking:
 *   - vector: drop cosine scores < VECTOR_RELEVANCE_FLOOR
 *   - structural / dependency: drop scores <= 0
 *   - fts / graph: kept as-is (presence is already a relevance signal)
 */
function addSource(
  fused: Map<string, FusedCandidate>,
  source: RetrievalSource,
  results: SourceResult[],
  weight: number
): void {
  if (weight <= 0 || results.length === 0) return;
  const ranked = rankSourceResults(source, results);
  for (let i = 0; i < ranked.length; i++) {
    const result = ranked[i];
    const rank = i + 1; // 1-based rank within this source
    const contribution = weight / (RRF_K + rank);
    if (contribution <= 0) continue;
    const existing = fused.get(result.chunkId) ?? {
      fusedScore: 0,
      sources: new Set<RetrievalSource>(),
      sourceScores: {},
      reasons: [],
    };
    existing.fusedScore += contribution;
    existing.sources.add(source);
    existing.sourceScores[source] = (existing.sourceScores[source] ?? 0) + contribution;
    for (const reason of result.reasons) {
      if (reason && !existing.reasons.includes(reason) && existing.reasons.length < 8) {
        existing.reasons.push(reason);
      }
    }
    fused.set(result.chunkId, existing);
  }
}

/**
 * Sort a source's results by score descending and apply that source's absolute
 * relevance floor. Returns the surviving results in rank order (rank = index+1).
 */
function rankSourceResults(source: RetrievalSource, results: SourceResult[]): SourceResult[] {
  return [...results]
    .filter((result) => Number.isFinite(result.score) && passesRelevanceFloor(source, result.score))
    .sort((a, b) => b.score - a.score);
}

function passesRelevanceFloor(source: RetrievalSource, score: number): boolean {
  if (source === 'vector') return score >= (vectorFloorOverride ?? VECTOR_RELEVANCE_FLOOR);
  if (source === 'structural' || source === 'dependency') return score > 0;
  // fts / graph: presence is the signal — keep as-is.
  return true;
}

function scaleDeterministicLexicalScore(score: number): number {
  if (!Number.isFinite(score) || score <= 0) return 0;
  return Math.min(8, Math.log1p(score) * 1.8);
}

interface SparseStructuralTerm {
  term: string;
  weight: number;
  origin: string;
}

const SPARSE_STOP_WORDS = new Set([
  'add', 'new', 'fix', 'how', 'why', 'what', 'where', 'when', 'does', 'using',
  'uses', 'use', 'support', 'supports', 'should', 'currently', 'actually',
  'properly', 'different', 'causing', 'flow', 'logic', 'large', 'files',
]);

const PATH_INTENT_STOP_WORDS = new Set([
  ...SPARSE_STOP_WORDS,
  'context',
  'count',
  'file',
  'files',
  'information',
  'show',
  'statistics',
  'total',
  'type',
  'types',
]);

/** Max corpus identifiers added per query term during corpus-derived expansion. */
const CORPUS_EXPANSION_PER_TERM = 6;

/**
 * Build a stem -> {corpus identifiers with that stem} index from the indexed
 * code symbols. This is the principled, repository-agnostic replacement for the
 * deleted hand-coded TERM_EXPANSIONS table: expansion targets are the symbols
 * that actually exist in THIS corpus, so the mechanism generalizes to any repo
 * instead of only matching this project's own names.
 */
function buildCorpusStemIndex(symbols: CodeSymbol[]): Map<string, Set<string>> {
  const index = new Map<string, Set<string>>();
  const addVocab = (raw: string) => {
    const term = normalizeSymbolName(raw);
    if (term.length <= 2 || SPARSE_STOP_WORDS.has(term)) return;
    const stem = stemSparseTerm(term);
    if (stem.length < 3) return;
    let set = index.get(stem);
    if (!set) {
      set = new Set<string>();
      index.set(stem, set);
    }
    set.add(term);
  };
  for (const symbol of symbols) {
    addVocab(symbol.name);
    for (const part of splitIdentifier(symbol.name)) addVocab(part);
  }
  return index;
}

// Sparse structural terms are derived from the query (tokens, identifiers,
// split-identifier parts, conservative stems) and OPTIONALLY expanded against a
// vocabulary derived from the indexed corpus itself. The earlier hand-coded
// TERM_EXPANSIONS / PHRASE_EXPANSIONS tables mapped generic words to THIS repo's
// own symbols (train-on-test contamination); corpusStemIndex generalizes by
// expanding a query term to the real corpus identifiers that share its stem
// (e.g. "scoring" -> corpus symbols "scorer"/"score"), whatever repo is indexed.
function buildSparseStructuralTerms(
  structuralQuery: StructuralQuery,
  corpusStemIndex?: Map<string, Set<string>>
): SparseStructuralTerm[] {
  const terms = new Map<string, SparseStructuralTerm>();
  const add = (value: string, weight: number, origin: string) => {
    const term = normalizeSymbolName(value);
    if (term.length <= 1 || SPARSE_STOP_WORDS.has(term)) return;
    const existing = terms.get(term);
    if (!existing || existing.weight < weight) {
      terms.set(term, { term, weight, origin });
    }
  };

  for (const term of [...structuralQuery.tokens, ...structuralQuery.identifierParts]) {
    add(term, 0.55, 'query');
    const stem = stemSparseTerm(term);
    if (stem !== term) add(stem, 0.45, 'stem');
  }
  for (const identifier of structuralQuery.identifiers) {
    add(identifier, 0.8, 'identifier');
    for (const part of splitIdentifier(identifier)) add(part, 0.55, 'identifier');
  }

  if (corpusStemIndex) {
    for (const { term, weight, origin } of [...terms.values()]) {
      if (origin === 'corpus') continue;
      const stem = stemSparseTerm(term);
      if (stem.length < 3) continue;
      const related = corpusStemIndex.get(stem);
      if (!related) continue;
      let added = 0;
      for (const corpusTerm of related) {
        if (corpusTerm === term) continue;
        add(corpusTerm, Math.min(0.5, weight * 0.7), 'corpus');
        if (++added >= CORPUS_EXPANSION_PER_TERM) break;
      }
    }
  }

  return [...terms.values()]
    .sort((a, b) => b.weight - a.weight)
    .slice(0, 40);
}

function buildPathIntentTerms(sparseTerms: SparseStructuralTerm[]): string[] {
  return [...new Set(sparseTerms
    .filter((term) => term.weight >= 0.8 && term.origin === 'identifier')
    .map((term) => term.term)
    .filter((term) => term.length > 2 && !PATH_INTENT_STOP_WORDS.has(term)))];
}

// Common code words that must not be naively stemmed (e.g. "string" -> "str",
// "bytes" -> "byt", "class" -> "clas"). Combined with the length>=4 guard below.
const STEM_DENYLIST = new Set([
  'class', 'status', 'address', 'process', 'access', 'express', 'async', 'await',
  'string', 'bytes', 'native', 'series', 'species', 'analysis', 'business', 'success',
]);

function stemSparseTerm(value: string): string {
  const term = normalizeSymbolName(value);
  if (STEM_DENYLIST.has(term)) return term;
  let stem = term;
  if (term.endsWith('ies') && term.length > 5) stem = `${term.slice(0, -3)}y`;
  else if (term.endsWith('ing') && term.length > 6) stem = term.slice(0, -3);
  else if (term.endsWith('ed') && term.length > 5) stem = term.slice(0, -2);
  else if (term.endsWith('es') && term.length > 5) stem = term.slice(0, -2);
  else if (term.endsWith('s') && term.length > 4 && !term.endsWith('ss')) stem = term.slice(0, -1);
  return stem.length >= 4 ? stem : term;
}

function scoreSparseStructuralFields(
  chunk: ContextChunk,
  terms: SparseStructuralTerm[],
  symbols: CodeSymbol[],
  references: CodeReference[],
  strongIdentifiers: Set<string> = new Set(),
  strongIdentifierCases: Set<string> = new Set()
): { score: number; reasons: string[] } {
  const path = chunk.path ?? '';
  const normalizedPath = normalizeSymbolName(path);
  const pathParts = new Set(tokenizeStructuralField(path));
  const basename = path.split('/').pop() ?? path;
  const basenameStem = basename.replace(/\.[^.]+$/, '');
  const basenameNormalized = normalizeSymbolName(basenameStem);
  const basenameParts = new Set(tokenizeStructuralField(basenameStem));
  const symbolFields = symbols.map((symbol) => ({
    name: symbol.name,
    normalized: normalizeSymbolName(symbol.name),
    kind: symbol.kind,
    parts: new Set(splitIdentifier(symbol.name).map(normalizeSymbolName)),
    signature: normalizeSymbolName(symbol.signature ?? ''),
    exported: symbol.isExported,
  }));
  const referenceFields = references.map((reference) => ({
    target: reference.target,
    normalized: normalizeSymbolName(reference.target),
    parts: new Set(splitIdentifier(reference.target).map(normalizeSymbolName)),
  }));

  let score = 0;
  const reasons: string[] = [];
  for (const term of terms) {
    const field = scoreSparseTerm(term, {
      normalizedPath,
      pathParts,
      basenameNormalized,
      basenameParts,
      symbolFields,
      referenceFields,
    });
    if (field.score <= 0) continue;
    const capMultiplier = field.reason.startsWith('sparse contract exact')
      ? 3.2
      : field.reason.startsWith('sparse symbol exact')
        ? 2.4
        : 1.6;
    score += Math.min(field.score, capMultiplier * term.weight);
    if (reasons.length < 5) reasons.push(field.reason);
  }

  const strongSymbolMatches = strongIdentifiers.size > 0
    ? symbolFields.filter((symbol) => strongIdentifiers.has(symbol.normalized))
    : [];
  if (strongSymbolMatches.length > 0) {
    score += 6 + Math.min(3, strongSymbolMatches.length * 0.75);
    if (reasons.length < 5) reasons.push(`sparse exact identifier symbol: ${strongSymbolMatches[0].name}`);
  }

  const strongCaseSymbolMatches = strongIdentifierCases.size > 0
    ? symbolFields.filter((symbol) => strongIdentifierCases.has(symbol.name))
    : [];
  if (strongCaseSymbolMatches.length > 0) {
    score += 3 + Math.min(2, strongCaseSymbolMatches.length * 0.5);
    if (reasons.length < 5) reasons.push(`sparse exact identifier case match: ${strongCaseSymbolMatches[0].name}`);
  }

  const strongReferenceMatches = strongIdentifiers.size > 0
    ? referenceFields.filter((reference) => strongIdentifiers.has(reference.normalized))
    : [];
  if (strongReferenceMatches.length > 0) {
    score += 2.2;
    if (reasons.length < 5) reasons.push(`sparse exact identifier reference: ${strongReferenceMatches[0].target}`);
  }

  const strongPathMatch = strongIdentifiers.size > 0
    && (strongIdentifiers.has(basenameNormalized) || [...basenameParts].some((part) => strongIdentifiers.has(part)));
  if (strongPathMatch) {
    score += 1.8;
    if (reasons.length < 5) reasons.push(`sparse exact identifier path: ${basenameStem}`);
  }

  const strongTextMatch = scoreStrongIdentifierText(chunk.text, strongIdentifiers);
  if (strongTextMatch.score > 0) {
    score += strongTextMatch.score;
    for (const reason of strongTextMatch.reasons) {
      if (reasons.length < 5) reasons.push(reason);
    }
  }

  const hasExactContract = reasons.some((reason) => reason.startsWith('sparse contract exact'));
  const hasStrongExactIdentifier = strongSymbolMatches.length > 0
    || strongReferenceMatches.length > 0
    || strongPathMatch
    || strongTextMatch.exact;
  const cap = hasStrongExactIdentifier ? 20 : hasExactContract ? 12 : 7;
  return { score: Math.min(cap, score), reasons };
}

function scoreStrongIdentifierText(
  text: string,
  strongIdentifiers: Set<string>
): { score: number; reasons: string[]; exact: boolean } {
  if (strongIdentifiers.size === 0 || text.length === 0) {
    return { score: 0, reasons: [], exact: false };
  }

  let score = 0;
  let exact = false;
  const reasons: string[] = [];
  for (const identifier of strongIdentifiers) {
    const escaped = escapeRegExp(identifier);
    const rightBoundary = `(?![A-Za-z0-9_$])`;
    const identifierBoundary = `(?:^|[^A-Za-z0-9_$])${escaped}${rightBoundary}`;
    const declarationPattern = new RegExp(
      `\\b(?:const|let|var)\\s+${escaped}${rightBoundary}\\s*(?::[^=;]+)?=|\\b(?:function|class|interface|type|def)\\s+${escaped}${rightBoundary}`,
      'i'
    );
    const fieldPattern = new RegExp(`${identifierBoundary}\\??\\s*:`, 'im');
    const occurrencePattern = new RegExp(identifierBoundary, 'gi');

    if (declarationPattern.test(text)) {
      score += 6.5;
      exact = true;
      if (reasons.length < 2) reasons.push(`sparse exact identifier declaration: ${identifier}`);
    } else if (fieldPattern.test(text)) {
      score += 2.2;
      exact = true;
      if (reasons.length < 2) reasons.push(`sparse exact identifier field: ${identifier}`);
    }

    const occurrenceCount = [...text.matchAll(occurrencePattern)].length;
    if (occurrenceCount > 0) {
      score += Math.min(1.5, occurrenceCount * 0.25);
      if (!exact && reasons.length < 2) {
        reasons.push(`sparse exact identifier text: ${identifier}`);
      }
    }
  }

  return { score, reasons, exact };
}

function escapeRegExp(value: string): string {
  return value.replace(/[.*+?^${}()|[\]\\]/g, '\\$&');
}

function scorePathIntent(
  chunk: ContextChunk,
  structuralQuery: StructuralQuery,
  expandedTerms: string[] = []
): { score: number; reasons: string[] } {
  const path = chunk.path ?? '';
  if (!path) return { score: 0, reasons: [] };

  const pathParts = new Set(tokenizeStructuralField(path));
  const basename = path.split('/').pop() ?? path;
  const basenameParts = new Set(tokenizeStructuralField(basename.replace(/\.[^.]+$/, '')));
  const terms = [...new Set([
    ...structuralQuery.tokens,
    ...structuralQuery.identifierParts,
    ...structuralQuery.identifiers.flatMap(splitIdentifier),
    ...expandedTerms,
  ]
    .map(normalizeSymbolName)
    .filter((term) => term.length > 2 && !PATH_INTENT_STOP_WORDS.has(term)))];

  let score = 0;
  const reasons: string[] = [];
  for (const term of terms) {
    if (basenameParts.has(term)) {
      score += 5;
      if (reasons.length < 3) reasons.push(`path intent filename match: ${term}`);
    } else if (pathParts.has(term)) {
      score += 8;
      if (reasons.length < 3) reasons.push(`path intent segment match: ${term}`);
    }
  }

  return { score: Math.min(12, score), reasons };
}

function scoreSparseTerm(
  term: SparseStructuralTerm,
  fields: {
    normalizedPath: string;
    pathParts: Set<string>;
    basenameNormalized: string;
    basenameParts: Set<string>;
    symbolFields: Array<{ name: string; normalized: string; kind: CodeSymbol['kind']; parts: Set<string>; signature: string; exported: boolean }>;
    referenceFields: Array<{ target: string; normalized: string; parts: Set<string> }>;
  }
): { score: number; reason: string } {
  const value = term.term;
  const weight = term.weight;
  let bestScore = 0;
  let bestReason = '';

  const consider = (score: number, reason: string) => {
    if (score > bestScore) {
      bestScore = score;
      bestReason = reason;
    }
  };

  if (fields.basenameNormalized === value) consider(1.05 * weight, `sparse path exact: ${value}`);
  if (fields.basenameParts.has(value)) consider(0.8 * weight, `sparse filename token: ${value}`);
  if (fields.pathParts.has(value)) consider(0.42 * weight, `sparse path token: ${value}`);
  if (fields.basenameNormalized === 'index') {
    const matchingSegment = [...fields.pathParts].find((part) => part !== 'index' && isSingularPluralMatch(value, part));
    if (matchingSegment) consider(1.1 * weight, `sparse module index segment: ${matchingSegment}`);
  }
  if (value.length >= 4 && fields.normalizedPath.includes(value)) consider(0.18 * weight, `sparse path partial: ${value}`);

  for (const symbol of fields.symbolFields) {
    const exported = symbol.exported ? 1.1 : 1;
    const contract = symbol.kind === 'interface' || symbol.kind === 'type' ? 2.1 : 1;
    if (symbol.normalized === value) {
      const reason = contract > 1 ? `sparse contract exact: ${symbol.name}` : `sparse symbol exact: ${symbol.name}`;
      consider((contract > 1 ? 1.5 : 1.2) * weight * exported * contract, reason);
    }
    if (symbol.parts.has(value)) consider(0.62 * weight * exported, `sparse symbol token: ${symbol.name}`);
    if (value.length >= 4 && symbol.normalized.includes(value)) consider(0.38 * weight * exported, `sparse symbol partial: ${symbol.name}`);
    if (value.length >= 4 && symbol.signature.includes(value)) consider(0.22 * weight * exported, `sparse signature token: ${symbol.name}`);
  }

  for (const reference of fields.referenceFields) {
    if (reference.normalized === value) consider(0.42 * weight, `sparse reference exact: ${reference.target}`);
    if (reference.parts.has(value)) consider(0.24 * weight, `sparse reference token: ${reference.target}`);
    if (value.length >= 4 && reference.normalized.includes(value)) consider(0.16 * weight, `sparse reference partial: ${reference.target}`);
  }

  return { score: bestScore, reason: bestReason };
}

function tokenizeStructuralField(value: string): string[] {
  return value
    .split(/[/. _:-]+/)
    .flatMap((part) => splitIdentifier(part))
    .map(normalizeSymbolName)
    .filter((part) => part.length > 1);
}

function isSingularPluralMatch(term: string, fieldPart: string): boolean {
  if (term === fieldPart) return true;
  if (term.length <= 2 || fieldPart.length <= 2) return false;
  if (`${term}s` === fieldPart || `${fieldPart}s` === term) return true;
  if (term.endsWith('ies') && `${term.slice(0, -3)}y` === fieldPart) return true;
  if (fieldPart.endsWith('ies') && `${fieldPart.slice(0, -3)}y` === term) return true;
  return false;
}

/**
 * Merge text-source result sets (FTS5/BM25 + the deterministic lexical fallback)
 * by summing scores per chunk, then sorting descending.
 *
 * WS0.3 proposed replacing this raw sum with a rank-based / normalized merge: the
 * two arms are on different scales (FTS5 negated-BM25 reals ~5–20, the lexical
 * fallback small integers 2/3/5…), so the sum lets BM25 magnitude dominate the
 * order and double-counts a chunk present in both. We tried both replacements
 * (weighted RRF; max-normalized weighted sum, lexical weight swept 0.2–1.0) and a
 * controlled same-session GPU before/after on django/typescript/rust. EVERY
 * replacement regressed the durable GPU structural Hits@1 edge by 0.01–0.02 on all
 * three corpora, because the two regimes want opposite things from the lexical
 * arm: deterministic `fts` recall wants it weighted HIGH (it adds path/substring
 * recall FTS5's unindexed-path tokenizer misses), while GPU `structural` top-1
 * wants it weighted LOW (it perturbs the top-1 the edge depends on). The raw sum
 * is a local optimum — BM25 magnitude dominates the ordering (protecting top-1)
 * while the lexical arm still contributes union members (recall) — so it is KEPT
 * by an evidence-backed decision. See benchmarks/COMMIT-DERIVED-FINDINGS.md
 * ("WS0.3 text-source merge"). A future merge may beat it only if it preserves
 * BM25 top-1 dominance without losing lexical recall (e.g. BM25-primary with
 * lexical-only chunks appended), validated on the GPU harness — not on the
 * deterministic gate alone, which cannot see the GPU-regime top-1 shift.
 *
 * Only the output ORDER is consumed downstream (`addSource` re-ranks by score),
 * so the summed magnitude is a ranking key, not a calibrated score.
 */
function mergeRawResults(resultSets: Array<Array<{ chunkId: string; score: number }>>): { chunkId: string; score: number }[] {
  const merged = new Map<string, number>();
  for (const results of resultSets) {
    for (const result of results) {
      merged.set(result.chunkId, (merged.get(result.chunkId) ?? 0) + result.score);
    }
  }
  return [...merged.entries()]
    .map(([chunkId, score]) => ({ chunkId, score }))
    .sort((a, b) => b.score - a.score);
}

import type {
  ContextChunk,
  ContextTier,
  DependencyLink,
  RoutingConfig,
  ScoreResult,
} from '../types/index.js';

export const DEFAULT_ROUTING_CONFIG: RoutingConfig = {
  weights: {
    semantic: 0.3,
    constraint: 0.25,
    recency: 0.2,
    redundancy: 0.1,
    dependency: 0.15,
  },
  thresholds: {
    hot: 0.7,
    warm: 0.4,
  },
};

export class ContextRouter {
  constructor(private config: RoutingConfig = DEFAULT_ROUTING_CONFIG) {}

  route(
    scores: Record<string, number>,
    reasons: Record<string, string[]>,
    chunks: ContextChunk[],
    dependencies: DependencyLink[],
    maxTokens?: number
  ): ScoreResult {
    const hot: string[] = [];
    const warm: string[] = [];
    const cold: string[] = [];
    const finalReasons: Record<string, string[]> = {};
    const tierMap = new Map<string, ContextTier>();
    const chunkMap = new Map(chunks.map((chunk) => [chunk.id, chunk]));
    const maxHotChunks = Math.max(1, Math.floor(chunks.length * 0.6));

    for (const chunk of chunks) {
      const score = scores[chunk.id] ?? 0;
      const chunkReasons = [...(reasons[chunk.id] ?? [])];

      let tier: ContextTier;
      if (score >= this.config.thresholds.hot) {
        tier = 'hot';
        chunkReasons.push(`score ${score.toFixed(3)} above hot threshold ${this.config.thresholds.hot}`);
      } else if (score >= this.config.thresholds.warm) {
        tier = 'warm';
        chunkReasons.push(`score ${score.toFixed(3)} above warm threshold ${this.config.thresholds.warm}`);
      } else {
        tier = 'cold';
        chunkReasons.push(`score ${score.toFixed(3)} below warm threshold ${this.config.thresholds.warm}`);
      }

      if (chunk.type === 'constraint' && tier !== 'hot' && score > 0.3) {
        tier = 'hot';
        chunkReasons.push('promoted to hot: constraint type');
      }

      if (chunk.type === 'instruction' && tier !== 'hot' && score > 0.5) {
        tier = 'hot';
        chunkReasons.push('promoted to hot: instruction type');
      }

      if (tier === 'hot' && chunkReasons.some((reason) => reason.includes('redundant'))) {
        tier = 'warm';
        chunkReasons.push('demoted to warm: redundant with other chunk');
      }

      tierMap.set(chunk.id, tier);
      finalReasons[chunk.id] = chunkReasons;
    }

    this.demoteLowestScoringHotChunks(
      tierMap,
      finalReasons,
      scores,
      chunks,
      maxHotChunks,
      'demoted to warm: hot tier capped at 60% of total chunks'
    );

    const depLookup = new Map<string, DependencyLink[]>();
    for (const dep of dependencies) {
      const fromLinks = depLookup.get(dep.fromId) ?? [];
      fromLinks.push(dep);
      depLookup.set(dep.fromId, fromLinks);

      const toLinks = depLookup.get(dep.toId) ?? [];
      toLinks.push(dep);
      depLookup.set(dep.toId, toLinks);
    }

    let changed = true;
    let iterations = 0;
    while (changed && iterations < 10 && this.getHotChunkIds(tierMap, chunks).length < maxHotChunks) {
      changed = false;
      iterations++;

      for (const chunk of chunks) {
        if (tierMap.get(chunk.id) !== 'hot') continue;
        if (this.getHotChunkIds(tierMap, chunks).length >= maxHotChunks) break;

        const links = depLookup.get(chunk.id) ?? [];
        for (const link of links) {
          if (this.getHotChunkIds(tierMap, chunks).length >= maxHotChunks) break;

          const otherId = link.fromId === chunk.id ? link.toId : link.fromId;
          if (tierMap.get(otherId) !== 'warm') continue;

          tierMap.set(otherId, 'hot');
          finalReasons[otherId].push('promoted to hot: dependency of hot chunk');
          changed = true;
        }
      }
    }

    this.demoteLowestScoringHotChunks(
      tierMap,
      finalReasons,
      scores,
      chunks,
      maxHotChunks,
      'demoted to warm: hot tier capped at 60% of total chunks'
    );

    if (maxTokens !== undefined) {
      let hotTokens = this.getHotTokens(tierMap, chunkMap);
      for (const chunkId of this.getHotChunkIds(tierMap, chunks).sort(
        (a, b) => (scores[a] ?? 0) - (scores[b] ?? 0)
      )) {
        if (hotTokens <= maxTokens) break;
        tierMap.set(chunkId, 'warm');
        finalReasons[chunkId].push('demoted to warm: hot tier exceeds token budget');
        hotTokens -= chunkMap.get(chunkId)?.tokensEstimate ?? 0;
      }
    }

    for (const chunk of chunks) {
      const tier = tierMap.get(chunk.id) ?? 'cold';
      if (tier === 'hot') hot.push(chunk.id);
      else if (tier === 'warm') warm.push(chunk.id);
      else cold.push(chunk.id);
    }

    return { hot, warm, cold, scores, reasons: finalReasons };
  }

  private demoteLowestScoringHotChunks(
    tierMap: Map<string, ContextTier>,
    reasons: Record<string, string[]>,
    scores: Record<string, number>,
    chunks: ContextChunk[],
    maxHotChunks: number,
    reason: string
  ): void {
    const hotChunkIds = this.getHotChunkIds(tierMap, chunks);
    if (hotChunkIds.length <= maxHotChunks) return;

    for (const chunkId of hotChunkIds
      .sort((a, b) => (scores[a] ?? 0) - (scores[b] ?? 0))
      .slice(0, hotChunkIds.length - maxHotChunks)) {
      tierMap.set(chunkId, 'warm');
      reasons[chunkId].push(reason);
    }
  }

  private getHotChunkIds(
    tierMap: Map<string, ContextTier>,
    chunks: ContextChunk[]
  ): string[] {
    return chunks
      .filter((chunk) => tierMap.get(chunk.id) === 'hot')
      .map((chunk) => chunk.id);
  }

  private getHotTokens(
    tierMap: Map<string, ContextTier>,
    chunkMap: Map<string, ContextChunk>
  ): number {
    let total = 0;
    for (const [chunkId, tier] of tierMap) {
      if (tier !== 'hot') continue;
      total += chunkMap.get(chunkId)?.tokensEstimate ?? 0;
    }
    return total;
  }
}

import type {
  TaskDescription,
  ContextChunk,
  RoutingConfig,
  EmbeddingProvider,
  TokenEstimator,
  DependencyLink,
} from '../types/index.js';
import { cosineSimilarity } from '../providers/deterministic-embedding.js';

export class ContextScorer {
  constructor(
    private config: RoutingConfig,
    private embeddingProvider: EmbeddingProvider,
    _tokenEstimator: TokenEstimator
  ) {}

  async scoreChunks(
    task: TaskDescription,
    chunks: ContextChunk[],
    dependencies: DependencyLink[] = []
  ): Promise<{ scores: Record<string, number>; reasons: Record<string, string[]> }> {
    const scores: Record<string, number> = {};
    const reasons: Record<string, string[]> = {};

    if (chunks.length === 0) return { scores, reasons };

    // Compute task embedding
    const taskEmbedding = await this.embeddingProvider.embed(task.text);

    // Compute all chunk embeddings
    const chunkEmbeddings = await this.embeddingProvider.embedBatch(
      chunks.map((c) => c.text)
    );

    const w = this.config.weights;
    const now = Date.now();
    const SEVEN_DAYS = 7 * 24 * 60 * 60 * 1000;

    // Build dependency lookup
    const depsFor = new Map<string, DependencyLink[]>();
    for (const dep of dependencies) {
      const arr = depsFor.get(dep.fromId) ?? [];
      arr.push(dep);
      depsFor.set(dep.fromId, arr);
      const arr2 = depsFor.get(dep.toId) ?? [];
      arr2.push(dep);
      depsFor.set(dep.toId, arr2);
    }

    for (let i = 0; i < chunks.length; i++) {
      const chunk = chunks[i];
      const chunkReasons: string[] = [];

      // Semantic similarity
      const semanticScore = cosineSimilarity(taskEmbedding, chunkEmbeddings[i]);
      chunkReasons.push(`semantic similarity: ${semanticScore.toFixed(3)}`);

      // Constraint score
      let constraintScore = 0.2;
      if (chunk.type === 'constraint') constraintScore = 1.0;
      else if (chunk.type === 'instruction') constraintScore = 0.5;
      chunkReasons.push(`type score: ${constraintScore.toFixed(2)} (${chunk.type})`);

      // Recency score (7-day linear decay)
      const age = now - chunk.timestamp;
      const recencyScore = Math.max(0, 1 - age / SEVEN_DAYS);
      chunkReasons.push(`recency: ${recencyScore.toFixed(3)}`);

      // Redundancy penalty
      let redundancyScore = 1;
      if (semanticScore > 0.95) {
        chunkReasons.push('redundancy skipped: semantic similarity already very high');
      } else {
        let redundancyPenalty = 0;
        let checkedNeighbors = 0;
        for (let j = 0; j < chunks.length; j++) {
          if (i === j) continue;
          if (checkedNeighbors >= 20 || redundancyPenalty >= 1) break;
          checkedNeighbors++;

          const sim = cosineSimilarity(chunkEmbeddings[i], chunkEmbeddings[j]);
          if (sim > 0.8) {
            redundancyPenalty = Math.min(1, redundancyPenalty + 0.3);
            chunkReasons.push(`redundant with chunk ${chunks[j].id.slice(0, 8)}`);
          }
        }
        redundancyScore = Math.max(0, 1 - redundancyPenalty);
      }

      // Dependency score: boost if linked to high-scoring chunks
      let dependencyScore = 0;
      const links = depsFor.get(chunk.id) ?? [];
      if (links.length > 0) {
        dependencyScore = Math.min(0.5, links.length * 0.15);
        chunkReasons.push(`dependency boost: +${dependencyScore.toFixed(2)} (${links.length} links)`);
      }

      // Weighted combination
      const total =
        w.semantic * semanticScore +
        w.constraint * constraintScore +
        w.recency * recencyScore +
        w.redundancy * redundancyScore +
        w.dependency * dependencyScore;

      // Clamp to [0, 1]
      const clamped = Math.max(0, Math.min(1, total));
      scores[chunk.id] = clamped;
      reasons[chunk.id] = chunkReasons;
    }

    // Second pass: dependency boost based on already-scored chunks
    for (const chunk of chunks) {
      const links = depsFor.get(chunk.id) ?? [];
      let boost = 0;
      for (const link of links) {
        const otherId = link.fromId === chunk.id ? link.toId : link.fromId;
        if (scores[otherId] !== undefined && scores[otherId] > 0.7) {
          boost += 0.1 * link.weight;
        }
      }
      if (boost > 0) {
        scores[chunk.id] = Math.min(1, scores[chunk.id] + boost);
        reasons[chunk.id].push(`dependency closure boost: +${boost.toFixed(3)}`);
      }
    }

    return { scores, reasons };
  }
}

import type { TokenEstimator } from '../types/index.js';
import { StructuralIndexer } from '../providers/structural-indexer.js';

/** Tracks lazy initialization state across calls. */
let indexerInstance: StructuralIndexer | null = null;
let initAttempted = false;
let available = false;

/**
 * Get (or lazily create) the structural indexer.
 * Returns null if tree-sitter is unavailable.
 */
function getIndexer(): StructuralIndexer | null {
  if (initAttempted) return available ? indexerInstance : null;
  initAttempted = true;

  if (process.env.CHUNK_TREE_SITTER !== '1') return null;

  indexerInstance = new StructuralIndexer({ timeoutMs: 5000 });
  available = true;
  return indexerInstance;
}

/** Reset state (for testing). */
export function resetTreeSitterChunker(): void {
  indexerInstance = null;
  initAttempted = false;
  available = false;
}

/**
 * Use tree-sitter to split code at AST boundaries.
 *
 * Calls the Python structural-indexer to get symbol ranges (functions, classes,
 * methods, etc.) and splits code along those boundaries. Symbols that fit within
 * maxTokens are kept whole; oversized symbols are recursively split.
 *
 * Returns null if tree-sitter is unavailable, so caller can fall back to regex.
 */
export async function splitCodeWithTreeSitter(
  text: string,
  maxTokens: number,
  overlapTokens: number,
  tokenEstimator: TokenEstimator,
  language?: string
): Promise<string[] | null> {
  const indexer = getIndexer();
  if (!indexer) return null;

  try {
    const extraction = await indexer.extract(text, language);
    if (extraction.backend !== 'tree-sitter') return null;

    return buildChunksFromSymbolRanges(
      text, extraction.symbols, maxTokens, overlapTokens, tokenEstimator
    );
  } catch {
    // Any error means we fall back to regex
    return null;
  }
}

/**
 * Find the line index where imports end.
 * Very similar to the logic in splitCode() already.
 */
function findImportEnd(lines: string[]): number {
  let end = 0;
  for (let i = 0; i < lines.length; i++) {
    const trimmed = lines[i].trim();
    if (trimmed.length === 0 && end === i) {
      end = i + 1;
      continue;
    }
    if (/^\s*(import\s|from\s|require\s*\(|#include\s|use\s)/.test(lines[i])) {
      end = i + 1;
    } else {
      break;
    }
  }
  return end;
}

/** Minimal symbol shape used for AST chunk boundaries — startLine/endLine only.
 * Both the Python sidecar (CodeSymbol) and the pure-JS web-tree-sitter source
 * feed boundaries through this so the boundary→chunk machinery is shared. */
export interface SymbolRange {
  startLine: number;
  endLine: number;
}

interface LineRange {
  start: number; // inclusive, 0-based line index
  end: number;   // exclusive, 0-based line index
  symbol: SymbolRange;
}

/**
 * Build code chunks from AST symbol ranges (startLine/endLine), independent of
 * how those ranges were produced (Python sidecar or pure-JS web-tree-sitter).
 * Splits along non-overlapping top-level boundaries, keeps the import block as a
 * prefix, packs small adjacent nodes together, and recursively splits oversized
 * nodes. Returns null if it can't produce more than one piece (caller falls back
 * to regex).
 */
export function buildChunksFromSymbolRanges(
  text: string,
  symbols: SymbolRange[],
  maxTokens: number,
  overlapTokens: number,
  tokenEstimator: TokenEstimator
): string[] | null {
  if (symbols.length === 0) return null;
  const lines = text.split('\n');
  const importEnd = findImportEnd(lines);
  const importBlock = lines.slice(0, importEnd).join('\n');
  const bodyStart = importEnd;

  const ranges = buildNonOverlappingRanges(symbols, bodyStart);
  const pieces = buildPieces(lines, ranges, bodyStart, maxTokens, tokenEstimator);
  if (pieces.length <= 1) return null;

  const chunked = packPiecesWithPrefix(pieces, importBlock, maxTokens, tokenEstimator);
  return applyOverlap(chunked, overlapTokens);
}

/**
 * Given symbols from tree-sitter, build non-overlapping sorted ranges.
 * For nested structures (method inside class), keep the outermost container
 * as a single unit unless it exceeds maxTokens.
 */
function buildNonOverlappingRanges(
  symbols: SymbolRange[],
  bodyStart: number
): LineRange[] {
  // Sort by startLine, then by size descending (prefer larger containers)
  const sorted = [...symbols].sort((a, b) => {
    if (a.startLine !== b.startLine) return a.startLine - b.startLine;
    // If same start, prefer the one that ends later (outer container)
    return b.endLine - a.endLine;
  });

  const ranges: LineRange[] = [];
  let lastEnd = bodyStart; // 0-based, exclusive

  for (const sym of sorted) {
    const start = sym.startLine - 1; // convert to 0-based
    const end = sym.endLine;         // endLine is already 1-based, so as exclusive index it's correct

    if (end <= lastEnd) continue; // fully contained in previous range

    // If this symbol starts before the last ended, extend or skip
    const clampedStart = Math.max(start, lastEnd);
    if (clampedStart >= end) continue;

    ranges.push({ start: clampedStart, end, symbol: sym });
    lastEnd = end;
  }

  return ranges;
}

/**
 * Build text pieces from the line ranges, including gaps between symbols.
 * Each piece is one AST node (or a group of small adjacent nodes).
 */
function buildPieces(
  lines: string[],
  ranges: LineRange[],
  bodyStart: number,
  maxTokens: number,
  tokenEstimator: TokenEstimator
): string[] {
  const pieces: string[] = [];
  let pos = bodyStart;

  for (const range of ranges) {
    // Capture any gap between pos and range.start as a preamble piece
    if (range.start > pos) {
      const gapText = lines.slice(pos, range.start).join('\n').trim();
      if (gapText) pieces.push(gapText);
    }

    const rangeText = lines.slice(range.start, range.end).join('\n');
    const rangeTokens = tokenEstimator.estimate(rangeText);

    if (rangeTokens <= maxTokens) {
      pieces.push(rangeText);
    } else {
      // Oversized symbol: split it by lines
      const subPieces = splitOversizedRange(lines, range.start, range.end, maxTokens, tokenEstimator);
      pieces.push(...subPieces);
    }

    pos = range.end;
  }

  // Trailing code after last symbol
  if (pos < lines.length) {
    const trailing = lines.slice(pos).join('\n').trim();
    if (trailing) pieces.push(trailing);
  }

  return pieces;
}

/**
 * Split an oversized AST node range into line-based chunks.
 * Tries to break at blank lines to avoid splitting mid-expression.
 */
function splitOversizedRange(
  lines: string[],
  start: number,
  end: number,
  maxTokens: number,
  tokenEstimator: TokenEstimator
): string[] {
  const pieces: string[] = [];
  let currentLines: string[] = [];
  let currentTokens = 0;

  for (let i = start; i < end; i++) {
    const line = lines[i];
    const lineTokens = tokenEstimator.estimate(line);

    if (currentTokens + lineTokens > maxTokens && currentLines.length > 0) {
      // Try to break at the last blank line in current batch
      const lastBlank = currentLines.reduce((acc, l, idx) => l.trim() === '' ? idx : acc, -1);
      if (lastBlank > 0) {
        pieces.push(currentLines.slice(0, lastBlank).join('\n'));
        currentLines = currentLines.slice(lastBlank + 1);
        currentTokens = tokenEstimator.estimate(currentLines.join('\n'));
      } else {
        pieces.push(currentLines.join('\n'));
        currentLines = [];
        currentTokens = 0;
      }
    }

    currentLines.push(line);
    currentTokens += lineTokens;
  }

  if (currentLines.length > 0) {
    pieces.push(currentLines.join('\n'));
  }

  return pieces;
}

function packPiecesWithPrefix(
  pieces: string[],
  importBlock: string,
  maxTokens: number,
  tokenEstimator: TokenEstimator
): string[] {
  const chunks: string[] = [];
  let current: string[] = [];

  const flushCurrent = () => {
    if (current.length === 0) return;
    chunks.push(formatCodeChunk(importBlock, current.join('\n\n')));
    current = [];
  };

  for (const piece of pieces) {
    if (!piece.trim()) continue;

    const candidate = [...current, piece].join('\n\n');
    if (tokenEstimator.estimate(formatCodeChunk(importBlock, candidate)) <= maxTokens) {
      current.push(piece);
      continue;
    }

    flushCurrent();
    if (tokenEstimator.estimate(formatCodeChunk(importBlock, piece)) <= maxTokens) {
      current.push(piece);
      continue;
    }

    chunks.push(...splitOversizedPiece(piece, importBlock, maxTokens, tokenEstimator));
  }

  flushCurrent();
  return chunks;
}

function splitOversizedPiece(
  piece: string,
  importBlock: string,
  maxTokens: number,
  tokenEstimator: TokenEstimator
): string[] {
  const prefix = codePrefix(importBlock);
  if (!prefix || tokenEstimator.estimate(prefix) >= maxTokens) {
    return splitTextByLines(piece, maxTokens, tokenEstimator);
  }

  const bodyMaxTokens = Math.max(1, maxTokens - tokenEstimator.estimate(prefix));
  return splitTextByLines(piece, bodyMaxTokens, tokenEstimator)
    .map((subPiece) => formatCodeChunk(importBlock, subPiece));
}

function splitTextByLines(
  text: string,
  maxTokens: number,
  tokenEstimator: TokenEstimator
): string[] {
  const chunks: string[] = [];
  let current: string[] = [];

  const flushCurrent = () => {
    if (current.length === 0) return;
    chunks.push(current.join('\n'));
    current = [];
  };

  for (const line of text.split('\n')) {
    const candidate = [...current, line].join('\n');
    if (tokenEstimator.estimate(candidate) <= maxTokens) {
      current.push(line);
      continue;
    }

    flushCurrent();
    if (tokenEstimator.estimate(line) <= maxTokens) {
      current.push(line);
      continue;
    }

    chunks.push(...splitLongLine(line, maxTokens, tokenEstimator));
  }

  flushCurrent();
  return chunks;
}

function splitLongLine(
  line: string,
  maxTokens: number,
  tokenEstimator: TokenEstimator
): string[] {
  const chunks: string[] = [];
  let start = 0;

  while (start < line.length) {
    let end = Math.min(line.length, start + Math.max(1, maxTokens * 4));
    while (end > start + 1 && tokenEstimator.estimate(line.slice(start, end)) > maxTokens) {
      end--;
    }
    chunks.push(line.slice(start, end));
    start = end;
  }

  return chunks;
}

function codePrefix(importBlock: string): string {
  const trimmed = importBlock.trim();
  return trimmed ? `${trimmed}\n\n` : '';
}

function formatCodeChunk(importBlock: string, body: string): string {
  const prefix = codePrefix(importBlock);
  const trimmedBody = body.trim();
  if (!prefix) return trimmedBody;
  return trimmedBody ? `${prefix}${trimmedBody}` : importBlock.trim();
}

/**
 * Apply overlap between chunks (same logic as in chunker.ts but for async context).
 */
function applyOverlap(
  chunks: string[],
  overlapTokens: number
): string[] {
  if (chunks.length <= 1 || overlapTokens <= 0) return chunks;

  const result: string[] = [];
  for (let i = 0; i < chunks.length; i++) {
    let chunk = chunks[i];
    if (i > 0) {
      const prev = chunks[i - 1];
      const overlapChars = overlapTokens * 4;
      const overlap = prev.slice(-overlapChars);
      const lastNewline = overlap.indexOf('\n');
      const trimmedOverlap = lastNewline >= 0 ? overlap.slice(lastNewline + 1) : overlap;
      if (trimmedOverlap.trim()) {
        chunk = `[...]\n${trimmedOverlap}${chunk}`;
      }
    }
    result.push(chunk);
  }

  return result;
}

import chokidar, { type FSWatcher } from 'chokidar';
import { readFileSync, existsSync, lstatSync } from 'node:fs';
import { isAbsolute, join, relative, resolve } from 'node:path';
import type { PipelineOrchestrator } from '../pipeline/orchestrator.js';
import { normalizeContextPath } from './ingester.js';

const DEFAULT_IGNORES = ['node_modules', '.git', 'dist'];
const BINARY_EXTENSIONS = ['.png', '.jpg', '.jpeg', '.gif', '.ico', '.woff', '.woff2', '.ttf', '.eot'];

export class FileWatcher {
  private watcher: FSWatcher | null = null;
  private pending = new Map<string, NodeJS.Timeout>();
  private gitignorePatterns: string[];

  constructor(
    private watchPath: string,
    private pipeline: PipelineOrchestrator
  ) {
    this.gitignorePatterns = this.loadGitignorePatterns();
  }

  start(): void {
    if (this.watcher) return;

    this.watcher = chokidar.watch(this.watchPath, {
      ignored: (path) => this.shouldIgnore(path),
      ignoreInitial: false,
      followSymlinks: false,
      persistent: true,
    });

    this.watcher.on('add', (filePath) => this.scheduleIngest(filePath, 'add'));
    this.watcher.on('change', (filePath) => this.scheduleIngest(filePath, 'change'));
    this.watcher.on('unlink', (filePath) => {
      const storagePath = this.storagePathFor(filePath);
      const deleted = this.pipeline.deleteChunksForPath(storagePath);
      process.stderr.write(`Unlinked ${filePath}; deleted ${deleted} stored chunks.\n`);
    });
    this.watcher.on('error', (error) => {
      process.stderr.write(`Watcher error: ${String(error)}\n`);
    });
  }

  stop(): void {
    for (const timeout of this.pending.values()) {
      clearTimeout(timeout);
    }
    this.pending.clear();

    void this.watcher?.close();
    this.watcher = null;
  }

  private scheduleIngest(filePath: string, event: 'add' | 'change'): void {
    if (this.shouldIgnore(filePath)) return;

    const pending = this.pending.get(filePath);
    if (pending) clearTimeout(pending);

    this.pending.set(
      filePath,
      setTimeout(() => {
        this.pending.delete(filePath);
        void this.ingestFile(filePath, event);
      }, 300)
    );
  }

  private async ingestFile(filePath: string, event: 'add' | 'change'): Promise<void> {
    try {
      if (!existsSync(filePath)) return;
      if (this.isSymlinkPath(filePath)) return;
      const content = readFileSync(filePath, 'utf-8');
      const storagePath = this.storagePathFor(filePath);
      if (event === 'change') {
        const result = await this.pipeline.reingestFile(storagePath, content);
        process.stderr.write(
          `Watched ${event}: ${filePath} (${result.reusedChunks} reused, ${result.createdChunks} created, ${result.deletedChunks} deleted)\n`
        );
      } else {
        await this.pipeline.ingest('file', content, undefined, storagePath);
        process.stderr.write(`Watched ${event}: ${filePath}\n`);
      }
    } catch (error) {
      process.stderr.write(`Failed to ingest ${filePath}: ${String(error)}\n`);
    }
  }

  private loadGitignorePatterns(): string[] {
    const gitignorePath = join(this.watchPath, '.gitignore');
    if (!existsSync(gitignorePath)) return [];

    try {
      return readFileSync(gitignorePath, 'utf-8')
        .split(/\r?\n/)
        .map((line) => line.trim())
        .filter((line) => line.length > 0 && !line.startsWith('#'));
    } catch {
      return [];
    }
  }

  private shouldIgnore(filePath: string): boolean {
    if (this.isSymlinkPath(filePath)) return true;

    if (DEFAULT_IGNORES.some((pattern) => filePath.includes(`/${pattern}/`) || filePath.endsWith(`/${pattern}`))) {
      return true;
    }

    if (BINARY_EXTENSIONS.some((extension) => filePath.endsWith(extension))) {
      return true;
    }

    return this.gitignorePatterns.some((pattern) => this.matchesPattern(filePath, pattern));
  }

  private matchesPattern(filePath: string, pattern: string): boolean {
    const normalized = pattern.replace(/^\//, '').replace(/\/$/, '');
    if (!normalized) return false;
    if (normalized.includes('*')) {
      const regex = new RegExp(
        normalized
          .replace(/[.+^${}()|[\]\\]/g, '\\$&')
          .replace(/\*/g, '.*')
      );
      return regex.test(filePath);
    }
    return filePath.includes(normalized);
  }

  private isSymlinkPath(filePath: string): boolean {
    try {
      return lstatSync(filePath).isSymbolicLink();
    } catch {
      return false;
    }
  }

  private storagePathFor(filePath: string): string {
    const relativePath = relative(resolve(this.watchPath), resolve(filePath));
    if (relativePath && !relativePath.startsWith('..') && !isAbsolute(relativePath)) {
      return normalizeContextPath(relativePath);
    }
    return normalizeContextPath(filePath);
  }
}

import { createRequire } from 'node:module';
import { dirname, join } from 'node:path';
import { existsSync } from 'node:fs';
import type { TokenEstimator } from '../types/index.js';
import { buildChunksFromSymbolRanges, type SymbolRange } from './tree-sitter-chunker.js';

/**
 * Pure-JS AST chunking via web-tree-sitter (WASM), with NO Python sidecar and NO
 * subprocess at chunk time. Boundaries come from the parse tree's top-level named
 * children; the shared boundary→chunk machinery in tree-sitter-chunker.ts turns
 * them into chunks. Grammars are prebuilt `.wasm` files (tree-sitter-wasms),
 * loaded from disk — so this works fully offline once vendored.
 *
 * Everything is lazily, dynamically imported and guarded: if web-tree-sitter or a
 * grammar is unavailable, every entry point returns null and the caller falls
 * back to the regex code splitter. This keeps offline CI green when the optional
 * WASM deps are absent.
 *
 * Gated behind CHUNK_TREE_SITTER=js (see chunker.ts). The Python-sidecar path
 * (CHUNK_TREE_SITTER=1) is unchanged.
 */

const require = createRequire(import.meta.url);

// Our language identifiers → tree-sitter-wasms grammar basenames.
const GRAMMAR_BY_LANGUAGE: Record<string, string> = {
  typescript: 'typescript',
  javascript: 'javascript',
  python: 'python',
  rust: 'rust',
  go: 'go',
  java: 'java',
};

// Node types to skip as top-level boundaries (comments / stray tokens carry no
// structure; they get folded into adjacent pieces by the packer anyway).
const SKIP_NODE_TYPES = new Set(['comment', 'line_comment', 'block_comment']);

interface WebTreeSitterParser {
  setLanguage(lang: unknown): void;
  parse(text: string): {
    rootNode: {
      namedChildren: Array<{
        type: string;
        startPosition: { row: number; column: number };
        endPosition: { row: number; column: number };
      }>;
    };
  };
}

let initState: 'pending' | 'ready' | 'unavailable' = 'pending';
let parser: WebTreeSitterParser | null = null;
let ParserClass: any = null;
const grammarCache = new Map<string, unknown>();

function findGrammarsDir(): string | null {
  // Prefer require.resolve of a known grammar; fall back to package.json dir.
  for (const probe of ['tree-sitter-wasms/out/tree-sitter-python.wasm', 'tree-sitter-wasms/package.json']) {
    try {
      const resolved = require.resolve(probe);
      const dir = probe.endsWith('package.json') ? join(dirname(resolved), 'out') : dirname(resolved);
      if (existsSync(dir)) return dir;
    } catch {
      // try next
    }
  }
  return null;
}

function findRuntimeWasm(): string | null {
  for (const probe of ['web-tree-sitter/tree-sitter.wasm', 'web-tree-sitter/package.json']) {
    try {
      const resolved = require.resolve(probe);
      const file = probe.endsWith('package.json') ? join(dirname(resolved), 'tree-sitter.wasm') : resolved;
      if (existsSync(file)) return file;
    } catch {
      // try next
    }
  }
  return null;
}

async function ensureParser(): Promise<WebTreeSitterParser | null> {
  if (initState === 'ready') return parser;
  if (initState === 'unavailable') return null;
  initState = 'unavailable'; // pessimistic until proven
  try {
    const mod: any = await import('web-tree-sitter');
    ParserClass = mod.default ?? mod;
    const runtimeWasm = findRuntimeWasm();
    await ParserClass.init(
      runtimeWasm ? { locateFile: () => runtimeWasm } : undefined
    );
    parser = new ParserClass() as WebTreeSitterParser;
    initState = 'ready';
    return parser;
  } catch {
    parser = null;
    return null;
  }
}

// Precondition: ensureParser() must have completed first — `ParserClass.Language`
// is undefined until `Parser.init()` has awaited in web-tree-sitter 0.20.8.
async function loadGrammar(language: string): Promise<unknown | null> {
  const basename = GRAMMAR_BY_LANGUAGE[language];
  if (!basename) return null;
  if (grammarCache.has(basename)) return grammarCache.get(basename);

  const dir = findGrammarsDir();
  if (!dir) return null;
  const wasmPath = join(dir, `tree-sitter-${basename}.wasm`);
  if (!existsSync(wasmPath)) return null;

  try {
    const lang = await ParserClass.Language.load(wasmPath);
    grammarCache.set(basename, lang);
    return lang;
  } catch {
    grammarCache.set(basename, null);
    return null;
  }
}

/** Reset cached state (for testing). */
export function resetWebTreeSitterChunker(): void {
  initState = 'pending';
  parser = null;
  ParserClass = null;
  grammarCache.clear();
}

/** True once an attempt established availability; false if WASM deps are absent. */
export function webTreeSitterAvailable(): boolean {
  return initState === 'ready';
}

/**
 * Split code at AST boundaries using pure-JS web-tree-sitter. Returns null (so the
 * caller falls back to regex) when the language is unsupported, the WASM deps are
 * missing, parsing fails, or the result would not exceed one piece.
 */
export async function splitCodeWithWebTreeSitter(
  text: string,
  maxTokens: number,
  overlapTokens: number,
  tokenEstimator: TokenEstimator,
  language?: string
): Promise<string[] | null> {
  if (!language) return null;
  const normalized = language.toLowerCase();
  if (!GRAMMAR_BY_LANGUAGE[normalized]) return null;

  const ts = await ensureParser();
  if (!ts) return null;

  const grammar = await loadGrammar(normalized);
  if (!grammar) return null;

  try {
    ts.setLanguage(grammar);
    const tree = ts.parse(text);
    const ranges: SymbolRange[] = [];
    for (const node of tree.rootNode.namedChildren) {
      if (SKIP_NODE_TYPES.has(node.type)) continue;
      const startLine = node.startPosition.row + 1;
      // Exclusive 0-based end line: if the node ends at column 0 the last content
      // line is the previous row; otherwise it is the end row itself. This col===0
      // special-case intentionally diverges from the Python sidecar's unconditional
      // end_point[0]+1 (structural-indexer.py), which over-extends by a line in the
      // col-0 case — so the two AST sources are not bit-identical by design.
      const endLine = node.endPosition.column === 0
        ? node.endPosition.row
        : node.endPosition.row + 1;
      if (endLine > startLine - 1) ranges.push({ startLine, endLine });
    }
    return buildChunksFromSymbolRanges(text, ranges, maxTokens, overlapTokens, tokenEstimator);
  } catch {
    return null;
  }
}

