const SYSTEM_PROMPT = `You are a context compression engine for a coding assistant. Your job is to compress engineering context into a structured summary.

Rules:
- Preserve ALL constraints verbatim — never rephrase a "must" or "never" rule
- Extract key facts as short bullet points (max 2 sentences each)
- For code, list the function/class signatures and what they do
- Be concise — this summary will be fed into a prompt window
- Output format:

CONSTRAINTS:
- <each constraint>

FACTS:
- <each fact>

CODE:
- <file: signature — what it does>

COVERAGE: <N> chunks from <sources>`;

function truncate(text: string, max: number): string {
  return text.length <= max ? text : `${text.slice(0, max - 1)}…`;
}

function buildDeterministicFallback(task: TaskDescription, chunks: ContextChunk[]): CompressionResult {
  const sourceChunkIds = chunks.map((c) => c.id);
  const retainedConstraints = chunks
    .filter((c) => c.type === 'constraint')
    .map((c) => truncate(c.text.trim(), 220));
  const retainedFacts = chunks
    .filter((c) => c.type === 'fact' || c.type === 'background')
    .flatMap((c) => c.text.split(/[.!?]\s/).slice(0, 2).map((s) => truncate(s.trim(), 180)))
    .slice(0, 8);

  const parts = [
    `Task: ${truncate(task.text, 220)}`,
    retainedConstraints.length > 0 ? `Constraints: ${retainedConstraints.join('; ')}` : '',
    retainedFacts.length > 0 ? `Facts: ${retainedFacts.join('; ')}` : '',
    `Coverage: ${chunks.length} chunks`,
  ].filter(Boolean);

  return {
    summary: parts.join('. ') + '.',
    retainedFacts,
    retainedConstraints,
    sourceChunkIds,
  };
}

export class LLMCompressionProvider implements CompressionProvider {
  private config: Required<Pick<LLMCompressionConfig, 'endpoint' | 'apiKey' | 'model' | 'maxTokens'>> & {
    headers: Record<string, string>;
    modelField: string;
    messagesField: string;
  };

  constructor(config: LLMCompressionConfig) {
    this.config = {
      endpoint: config.endpoint,
      apiKey: config.apiKey,
      model: config.model,
      maxTokens: config.maxTokens ?? 500,
      headers: config.headers ?? {},
      modelField: config.modelField ?? 'model',
      messagesField: config.messagesField ?? 'messages',
    };
  }

  async compress(task: TaskDescription, chunks: ContextChunk[]): Promise<CompressionResult> {
    if (chunks.length === 0) {
      return { summary: '', retainedFacts: [], retainedConstraints: [], sourceChunkIds: [] };
    }

    const fallback = buildDeterministicFallback(task, chunks);
    const sourceChunkIds = chunks.map((c) => c.id);

    // Build the user message from chunk content
    const chunkTexts = chunks.map((c) => {
      const header = c.path
        ? `[${c.type}${c.path ? ` ${c.path}` : ''}]`
        : `[${c.type}]`;
      return `${header}\n${truncate(c.text, 2000)}`;
    });

    const userMessage = [
      `Task: ${task.text}`,
      '',
      '--- CONTEXT TO COMPRESS ---',
      ...chunkTexts,
      '--- END CONTEXT ---',
      '',
      'Compress the above context into a structured summary.',
    ].join('\n');

    try {
      const body: Record<string, unknown> = {
        [this.config.modelField]: this.config.model,
        [this.config.messagesField]: [
          { role: 'system', content: SYSTEM_PROMPT },
          { role: 'user', content: userMessage },
        ],
        max_tokens: this.config.maxTokens,
        temperature: 0,
      };

      const response = await fetch(this.config.endpoint, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          Authorization: `Bearer ${this.config.apiKey}`,
          ...this.config.headers,
        },
        body: JSON.stringify(body),
      });

      if (!response.ok) {
        const errorText = await response.text().catch(() => 'unknown error');
        console.error(`LLM compression API error (${response.status}): ${errorText}`);
        return fallback;
      }

      const data = await response.json() as Record<string, unknown>;
      const choices = data.choices as Array<{ message?: { content?: string } }> | undefined;
      const content = choices?.[0]?.message?.content?.trim();

      if (!content) {
        return fallback;
      }

      // Parse structured output for facts/constraints
      const retainedConstraints = extractSection(content, 'CONSTRAINTS');
      const retainedFacts = extractSection(content, 'FACTS');

      return {
        summary: content,
        retainedFacts,
        retainedConstraints,
        sourceChunkIds,
      };
    } catch (err) {
      console.error('LLM compression error:', err instanceof Error ? err.message : String(err));
      return fallback;
    }
  }
}

function extractSection(text: string, heading: string): string[] {
  const lines = text.split('\n');
  const items: string[] = [];
  let inSection = false;

  for (const line of lines) {
    const trimmed = line.trim();
    if (trimmed.toUpperCase().startsWith(heading)) {
      inSection = true;
      continue;
    }
    // New section header — stop
    if (inSection && /^[A-Z]+:/.test(trimmed)) {
      break;
    }
    if (inSection && trimmed.startsWith('- ')) {
      items.push(trimmed.slice(2));
    }
  }

  return items;
}

/**
 * LLMLingua Compression Provider
 *
 * Token-level compression via LLMLingua Python subprocess.
 * Similar to GpuEmbeddingProvider — JSON-RPC over stdin/stdout.
 *
 * Usage: Set COMPRESSION_PROVIDER=llmlingua
 */

import { spawn, type ChildProcess } from 'node:child_process';
import type { CompressionProvider, CompressionResult, TaskDescription, ContextChunk } from '../types/index.js';

interface PendingRequest {
  resolve: (value: any) => void;
  reject: (reason: any) => void;
}

export class LlmLinguaCompressionProvider implements CompressionProvider {
  private process: ChildProcess | null = null;
  private pending = new Map<number, PendingRequest>();
  private nextId = 0;
  private buffer = '';
  private ready = false;

  constructor(
    private model = process.env.LLMLINGUA_MODEL ?? 'microsoft/llmlingua-2-xlm-roberta-large-meetingbank',
    private pythonPath = process.env.PYTHON_PATH ?? 'python3',
    private compressionRate = parseFloat(process.env.LLMLINGUA_RATE ?? '0.5'),
  ) {}

  private ensureProcess(): Promise<void> {
    if (this.process && this.ready) return Promise.resolve();

    return new Promise((resolve, reject) => {
      const timeout = setTimeout(() => {
        reject(new Error('LLMLingua compressor timed out waiting for ready signal'));
      }, 60_000);

      this.process = spawn(this.pythonPath, [
        'scripts/llmlingua-compressor.py',
        '--model', this.model,
      ], {
        stdio: ['pipe', 'pipe', 'pipe'],
        env: { ...process.env },
      });

      this.process.stdout!.on('data', (data: Buffer) => {
        this.buffer += data.toString();
        const lines = this.buffer.split('\n');
        this.buffer = lines.pop() ?? '';

        for (const line of lines) {
          if (!line.trim()) continue;
          try {
            const msg = JSON.parse(line);
            const pending = this.pending.get(msg.id);
            if (pending) {
              this.pending.delete(msg.id);
              if (msg.error) pending.reject(new Error(msg.error));
              else pending.resolve(msg.result);
            }
          } catch { /* ignore partial JSON */ }
        }
      });

      this.process.stderr!.on('data', (data: Buffer) => {
        const text = data.toString().trim();
        if (text.includes('ready')) {
          this.ready = true;
          clearTimeout(timeout);
          resolve();
        }
      });

      this.process.on('exit', (code) => {
        if (!this.ready) {
          clearTimeout(timeout);
          reject(new Error(`LLMLingua compressor exited before ready (code ${code})`));
        }
      });
    });
  }

  private async rpc(method: string, params: Record<string, unknown>): Promise<any> {
    await this.ensureProcess();
    const id = this.nextId++;

    return new Promise((resolve, reject) => {
      this.pending.set(id, { resolve, reject });
      this.process!.stdin!.write(JSON.stringify({ id, method, params }) + '\n');

      setTimeout(() => {
        if (this.pending.has(id)) {
          this.pending.delete(id);
          reject(new Error(`RPC timeout: ${method}`));
        }
      }, 30_000);
    });
  }

  async compress(_task: TaskDescription, chunks: ContextChunk[]): Promise<CompressionResult> {
    const context = chunks.map((c) => c.text).join('\n\n');

    const result = await this.rpc('compress', {
      context,
      rate: this.compressionRate,
    });

    return {
      summary: result.compressed,
      retainedFacts: [],
      retainedConstraints: [],
      sourceChunkIds: chunks.map((c) => c.id),
    };
  }

  close(): void {
    if (this.process) {
      this.process.kill();
      this.process = null;
      this.ready = false;
    }
  }
}

import type {
  CompressionProvider,
  CompressionResult,
  ContextChunk,
  TaskDescription,
} from '../types/index.js';
import { env, pipeline } from '@huggingface/transformers';

env.allowLocalModels = true;
env.localModelPath = process.env.MODEL_PATH ?? './data/models';
env.useBrowserCache = false;

const STOP_WORDS = new Set([
  'about', 'after', 'again', 'against', 'along', 'also', 'because', 'before', 'being', 'between',
  'could', 'first', 'from', 'have', 'into', 'just', 'more', 'most', 'only', 'other', 'over',
  'same', 'should', 'some', 'such', 'than', 'that', 'their', 'them', 'then', 'there', 'these',
  'this', 'those', 'through', 'under', 'very', 'what', 'when', 'where', 'which', 'while', 'with',
  'would', 'your', 'task', 'code', 'file', 'files', 'text', 'chunk', 'chunks'
]);

function splitSentences(text: string): string[] {
  return text
    .replace(/\s+/g, ' ')
    .split(/(?<=[.!?])\s+/)
    .map((sentence) => sentence.trim())
    .filter(Boolean);
}

function truncate(text: string, maxLength: number): string {
  return text.length <= maxLength ? text : `${text.slice(0, maxLength - 1)}…`;
}

function extractCodeSignatures(text: string): string[] {
  const lines = text.split('\n').map((line) => line.trim()).filter(Boolean);
  const matches = lines.filter((line) =>
    /^(export\s+)?(async\s+)?function\s+\w+|^class\s+\w+|^(export\s+)?interface\s+\w+|^(export\s+)?type\s+\w+|^(export\s+)?(const|let|var)\s+\w+\s*=\s*(async\s*)?\([^)]*\)\s*=>/.test(line)
  );
  return matches.slice(0, 6).map((line) => truncate(line, 120));
}

function extractKeywords(task: TaskDescription, chunks: ContextChunk[]): string[] {
  const counts = new Map<string, number>();
  const input = [task.text, ...chunks.map((chunk) => chunk.text)].join(' ').toLowerCase();
  for (const word of input.match(/[a-z][a-z0-9_-]{3,}/g) ?? []) {
    if (STOP_WORDS.has(word)) continue;
    counts.set(word, (counts.get(word) ?? 0) + 1);
  }
  return [...counts.entries()]
    .sort((a, b) => b[1] - a[1] || a[0].localeCompare(b[0]))
    .slice(0, 8)
    .map(([word]) => word);
}

export class LocalCompressionProvider implements CompressionProvider {
  private useLocalModel = process.env.COMPRESSION_PROVIDER === 'local';
  private modelPipeline: unknown | null = null;
  private loading: Promise<unknown> | null = null;

  constructor(private modelId: string = process.env.COMPRESSION_MODEL ?? 'Xenova/bge-small-en-v1.5') {}

  private async getPipeline(): Promise<unknown> {
    if (this.modelPipeline) return this.modelPipeline;
    if (this.loading) return this.loading;

    this.loading = pipeline('text2text-generation', this.modelId, { dtype: 'fp32' });
    this.modelPipeline = await this.loading;
    return this.modelPipeline;
  }

  private buildDeterministicSummary(task: TaskDescription, chunks: ContextChunk[]): CompressionResult {
    const sourceChunkIds = chunks.map((chunk) => chunk.id);
    const retainedConstraints = chunks
      .filter((chunk) => chunk.type === 'constraint')
      .map((chunk) => truncate(chunk.text.trim(), 220));
    const retainedFacts = chunks
      .filter((chunk) => chunk.type === 'fact' || chunk.type === 'background' || chunk.type === 'reference')
      .flatMap((chunk) => splitSentences(chunk.text).slice(0, 2).map((sentence) => truncate(sentence, 180)))
      .slice(0, 8);
    const codeSignatures = chunks
      .filter((chunk) => chunk.type === 'code')
      .flatMap((chunk) => extractCodeSignatures(chunk.text).map((signature) =>
        chunk.path ? `${chunk.path}: ${signature}` : signature
      ))
      .slice(0, 8);
    const keywords = extractKeywords(task, chunks);
    const sections = [
      `Task: ${truncate(task.text, 220)}`,
      keywords.length > 0 ? `Keywords: ${keywords.join(', ')}` : '',
      retainedConstraints.length > 0 ? `Constraints:\n- ${retainedConstraints.join('\n- ')}` : '',
      retainedFacts.length > 0 ? `Facts:\n- ${retainedFacts.join('\n- ')}` : '',
      codeSignatures.length > 0 ? `Code signatures:\n- ${codeSignatures.join('\n- ')}` : '',
      `Coverage: ${chunks.length} chunks, ${new Set(sourceChunkIds).size} unique sources`,
    ].filter(Boolean);

    return {
      summary: sections.join('\n\n'),
      retainedFacts,
      retainedConstraints,
      sourceChunkIds,
    };
  }

  async compress(task: TaskDescription, chunks: ContextChunk[]): Promise<CompressionResult> {
    const fallback = this.buildDeterministicSummary(task, chunks);
    if (!this.useLocalModel || chunks.length === 0) {
      return fallback;
    }

    try {
      const model = await this.getPipeline();
      const prompt = [
        'Summarize the following engineering context into constraints, facts, and code references.',
        `Task: ${task.text}`,
        fallback.summary,
      ].join('\n\n');
      const result = await (model as (input: string, options?: Record<string, unknown>) => Promise<unknown>)(
        prompt,
        { max_new_tokens: 180 }
      );
      const generatedText = Array.isArray(result)
        ? String((result[0] as { generated_text?: string }).generated_text ?? '')
        : '';
      if (!generatedText.trim()) {
        return fallback;
      }
      return {
        ...fallback,
        summary: `${generatedText.trim()}\n\n${fallback.summary}`,
      };
    } catch {
      return fallback;
    }
  }
}

import type { EmbeddingProvider } from '../types/index.js';
import { pipeline, env } from '@huggingface/transformers';

// Configure local model caching
env.allowLocalModels = true;
env.localModelPath = process.env.MODEL_PATH ?? './data/models';
env.useBrowserCache = false;

type EmbeddingPipeline = Awaited<ReturnType<typeof pipeline<'feature-extraction'>>>;

export class LocalEmbeddingProvider implements EmbeddingProvider {
  readonly quality = 'local' as const;
  private pipe: EmbeddingPipeline | null = null;
  private loading: Promise<EmbeddingPipeline> | null = null;

  constructor(private modelId: string = 'Xenova/bge-small-en-v1.5') {}

  private async getPipeline(): Promise<EmbeddingPipeline> {
    if (this.pipe) return this.pipe;
    if (this.loading) return this.loading;

    this.loading = pipeline('feature-extraction', this.modelId, {
      dtype: 'fp32',
      progress_callback: (progress: { status: string; progress?: number; file?: string }) => {
        if (progress.status === 'progress' && progress.progress !== undefined) {
          process.stderr?.write?.(
            `\rDownloading model ${this.modelId}: ${progress.file ?? ''} ${Math.round(progress.progress)}%`
          );
        } else if (progress.status === 'done') {
          process.stderr?.write?.('\n');
        }
      },
    });

    this.pipe = await this.loading;
    return this.pipe;
  }

  async embed(text: string): Promise<number[]> {
    const pipe = await this.getPipeline();
    const output = await pipe(text, { pooling: 'mean', normalize: true });
    return Array.from(output.data as Float32Array);
  }

  async embedBatch(texts: string[]): Promise<number[][]> {
    const results: number[][] = [];
    // Process sequentially to avoid memory pressure on large batches
    for (const text of texts) {
      results.push(await this.embed(text));
    }
    return results;
  }
}

/** Pre-download a model to the local cache */
export async function downloadModel(modelId: string = 'Xenova/bge-small-en-v1.5'): Promise<void> {
  console.log(`Downloading model: ${modelId}`);
  console.log(`Cache path: ${env.localModelPath}`);

  const pipe = await pipeline('feature-extraction', modelId, {
    dtype: 'fp32',
    progress_callback: (progress: { status: string; progress?: number; file?: string }) => {
      if (progress.status === 'progress' && progress.progress !== undefined) {
        process.stderr?.write?.(
          `\r  ${progress.file ?? 'model'}: ${Math.round(progress.progress)}%`
        );
      } else if (progress.status === 'done') {
        process.stderr?.write?.(` ✓\n`);
      } else if (progress.status === 'ready') {
        console.log(`  Model loaded: ${modelId}`);
      }
    },
  });

  // Run a test embedding to verify it works
  const testOutput = await pipe('test', { pooling: 'mean', normalize: true });
  console.log(`  Embedding dimensions: ${testOutput.dims.at(-1)}`);
  console.log(`  Model ready: ${modelId}`);
}

import { spawn } from 'node:child_process';
import { randomUUID } from 'node:crypto';
import { existsSync } from 'node:fs';
import { dirname, join } from 'node:path';
import { fileURLToPath } from 'node:url';
import type {
  CodeReference,
  CodeReferenceKind,
  CodeSymbol,
  CodeSymbolKind,
} from '../types/index.js';

export interface StructuralExtraction {
  symbols: CodeSymbol[];
  references: CodeReference[];
  backend: 'tree-sitter' | 'regex-fallback';
}

export interface StructuralIndexerOptions {
  python?: string;
  timeoutMs?: number;
  disableSubprocess?: boolean;
}

const SUPPORTED_LANGUAGES = new Set([
  'typescript',
  'javascript',
  'python',
  'rust',
  'go',
  'java',
]);

const CONTROL_WORDS = new Set([
  'if',
  'for',
  'while',
  'switch',
  'catch',
  'return',
  'throw',
  'else',
  'try',
  'do',
  'new',
  'function',
  'class',
  'interface',
  'type',
  'const',
  'let',
  'var',
  'pub',
  'fn',
  'func',
  'def',
  'elif',
  'except',
  'finally',
  'with',
  'lambda',
  'await',
  'yield',
]);

const IGNORED_CALL_TARGETS = new Set([
  ...CONTROL_WORDS,
  'console',
  'log',
  'debug',
  'info',
  'warn',
  'error',
  'require',
  'import',
  'super',
]);

type AddSymbol = (
  name: string,
  kind: CodeSymbolKind,
  index: number,
  signature: string,
  isExported: boolean,
  metadata?: Record<string, unknown>
) => void;

type AddReference = (
  target: string,
  kind: CodeReferenceKind,
  index: number,
  metadata?: Record<string, unknown>
) => void;

export function isSupportedCodeLanguage(language?: string): boolean {
  return language !== undefined && SUPPORTED_LANGUAGES.has(language.toLowerCase());
}

export function normalizeIdentifier(value: string): string {
  return value.toLowerCase().replace(/[^a-z0-9_$./:-]/g, '');
}

export function normalizeSymbolName(value: string): string {
  return value.toLowerCase().replace(/[^a-z0-9_$]/g, '');
}

export function splitIdentifier(value: string): string[] {
  return value
    .replace(/([a-z0-9])([A-Z])/g, '$1 $2')
    .replace(/[_$./:-]+/g, ' ')
    .toLowerCase()
    .split(/\s+/)
    .filter((part) => part.length > 1);
}

export class StructuralIndexer {
  private subprocessAvailable: boolean | undefined;

  constructor(private options: StructuralIndexerOptions = {}) {}

  async extract(text: string, language?: string, filePath?: string): Promise<StructuralExtraction> {
    if (!isSupportedCodeLanguage(language)) {
      return { symbols: [], references: [], backend: 'regex-fallback' };
    }

    const normalizedLanguage = language!.toLowerCase();
    if (!this.options.disableSubprocess && process.env.SPACEFOLDING_DISABLE_AST_SUBPROCESS !== '1') {
      const pythonResult = await this.tryPythonExtractor(text, normalizedLanguage, filePath);
      if (pythonResult) return pythonResult;
    }

    return {
      ...extractStructureFallback(text, normalizedLanguage, filePath),
      backend: 'regex-fallback',
    };
  }

  private async tryPythonExtractor(
    text: string,
    language: string,
    filePath?: string
  ): Promise<StructuralExtraction | null> {
    if (this.subprocessAvailable === false) return null;

    const script = findPythonScript();
    if (!script) {
      this.subprocessAvailable = false;
      return null;
    }

    try {
      const result = await runPythonStructuralExtractor(
        this.options.python ?? process.env.PYTHON ?? 'python3',
        script,
        text,
        language,
        filePath,
        this.options.timeoutMs ?? 2000
      );
      this.subprocessAvailable = true;
      const fallback = extractStructureFallback(text, language, filePath);
      const symbols = mergeSymbols(
        result.symbols.map((symbol) => normalizeSymbol(symbol, filePath, language)),
        fallback.symbols
      );
      const references = filterLocalCallReferences(
        mergeReferences(
          result.references.map((reference) => normalizeReference(reference, filePath, language)),
          fallback.references
        ),
        symbols
      );
      return {
        symbols,
        references,
        backend: 'tree-sitter',
      };
    } catch {
      this.subprocessAvailable = false;
      return null;
    }
  }
}

export function extractStructureFallback(
  text: string,
  language?: string,
  filePath?: string
): { symbols: CodeSymbol[]; references: CodeReference[] } {
  const normalizedLanguage = language?.toLowerCase();
  const lines = text.split(/\r?\n/);
  const symbols: CodeSymbol[] = [];
  const references: CodeReference[] = [];
  const seenSymbols = new Set<string>();
  const seenReferences = new Set<string>();
  const pythonClassIndents: number[] = [];

  const addSymbol = (
    name: string,
    kind: CodeSymbolKind,
    index: number,
    signature: string,
    isExported: boolean,
    metadata: Record<string, unknown> = {}
  ) => {
    if (!name || CONTROL_WORDS.has(name)) return;
    const startLine = index + 1;
    const key = `${kind}:${name}:${startLine}`;
    if (seenSymbols.has(key)) return;
    seenSymbols.add(key);
    symbols.push({
      id: randomUUID(),
      path: filePath,
      language: normalizedLanguage,
      name,
      normalizedName: normalizeSymbolName(name),
      kind,
      signature: signature.trim(),
      startLine,
      endLine: findBlockEndLine(lines, index, normalizedLanguage),
      isExported,
      metadata,
    });
  };

  const addReference = (
    target: string,
    kind: CodeReferenceKind,
    index: number,
    metadata: Record<string, unknown> = {}
  ) => {
    const cleanTarget = target.trim();
    if (!cleanTarget) return;
    const startLine = index + 1;
    const key = `${kind}:${cleanTarget}:${startLine}`;
    if (seenReferences.has(key)) return;
    seenReferences.add(key);
    references.push({
      id: randomUUID(),
      path: filePath,
      language: normalizedLanguage,
      target: cleanTarget,
      normalizedTarget: normalizeIdentifier(cleanTarget),
      kind,
      startLine,
      endLine: startLine,
      metadata,
    });
  };

  for (let i = 0; i < lines.length; i++) {
    const line = lines[i];
    const trimmed = line.trim();
    if (trimmed.length === 0 || trimmed.startsWith('//') || trimmed.startsWith('#')) continue;

    switch (normalizedLanguage) {
      case 'typescript':
      case 'javascript':
        extractJsLine(trimmed, line, i, addSymbol, addReference);
        break;
      case 'python':
        prunePythonClassStack(pythonClassIndents, line);
        extractPythonLine(trimmed, line, i, pythonClassIndents.length > 0, addSymbol, addReference);
        if (/^class\s+[A-Za-z_][\w]*\b/.test(trimmed)) {
          pythonClassIndents.push(leadingSpaces(line));
        }
        break;
      case 'rust':
        extractRustLine(trimmed, i, addSymbol, addReference);
        break;
      case 'go':
        extractGoLine(trimmed, i, addSymbol, addReference);
        break;
      case 'java':
        extractJavaLine(trimmed, i, addSymbol, addReference);
        break;
    }
  }

  return {
    symbols: symbols.sort((a, b) => a.startLine - b.startLine || a.name.localeCompare(b.name)),
    references: filterLocalCallReferences(references, symbols)
      .sort((a, b) => a.startLine - b.startLine || a.target.localeCompare(b.target)),
  };
}

function extractJsLine(
  line: string,
  originalLine: string,
  index: number,
  addSymbol: AddSymbol,
  addReference: AddReference
): void {
  const excludedCalls = new Set<string>();

  for (const pattern of [
    /\bfrom\s+['"]([^'"]+)['"]/g,
    /\bimport\s*\(\s*['"]([^'"]+)['"]\s*\)/g,
    /\brequire\s*\(\s*['"]([^'"]+)['"]\s*\)/g,
    /^\s*import\s+['"]([^'"]+)['"]/g,
  ]) {
    for (const match of line.matchAll(pattern)) addReference(match[1], 'import', index);
  }

  extractJsExportReferences(line, index, addReference);
  extractJsInheritanceReferences(line, index, addReference);

  const isExported = /\bexport\b/.test(line);
  const functionMatch = line.match(/^(?:export\s+)?(?:default\s+)?(?:async\s+)?function\s+([A-Za-z_$][\w$]*)\s*\(/);
  if (functionMatch) {
    addSymbol(functionMatch[1], 'function', index, line, isExported);
    excludedCalls.add(functionMatch[1]);
    if (isExported) addReference(functionMatch[1], 'export', index);
  } else if (line.match(/^(?:module\.)?exports(?:\.[A-Za-z_$][\w$]*)?\s*=\s*(?:async\s+)?function\s+([A-Za-z_$][\w$]*)\s*\(/)) {
    const moduleFunctionMatch = line.match(/^(?:module\.)?exports(?:\.[A-Za-z_$][\w$]*)?\s*=\s*(?:async\s+)?function\s+([A-Za-z_$][\w$]*)\s*\(/);
    if (moduleFunctionMatch) {
      addSymbol(moduleFunctionMatch[1], 'function', index, line, true);
      addReference(moduleFunctionMatch[1], 'export', index);
      excludedCalls.add(moduleFunctionMatch[1]);
    }
  } else if (line.match(/^(?:module\.)?exports\.([A-Za-z_$][\w$]*)\s*=/)) {
    const commonJsExportMatch = line.match(/^(?:module\.)?exports\.([A-Za-z_$][\w$]*)\s*=/);
    if (commonJsExportMatch) {
      addReference(commonJsExportMatch[1], 'export', index);
    }
  } else if (line.match(/^(?:export\s+)?(?:default\s+)?class\s+([A-Za-z_$][\w$]*)\b/)) {
    const classMatch = line.match(/^(?:export\s+)?(?:default\s+)?class\s+([A-Za-z_$][\w$]*)\b/);
    if (!classMatch) return;
    addSymbol(classMatch[1], 'class', index, line, isExported);
    excludedCalls.add(classMatch[1]);
    if (isExported) addReference(classMatch[1], 'export', index);
  } else if (line.match(/^(?:export\s+)?interface\s+([A-Za-z_$][\w$]*)\b/)) {
    const interfaceMatch = line.match(/^(?:export\s+)?interface\s+([A-Za-z_$][\w$]*)\b/);
    if (!interfaceMatch) return;
    addSymbol(interfaceMatch[1], 'interface', index, line, isExported);
    excludedCalls.add(interfaceMatch[1]);
    if (isExported) addReference(interfaceMatch[1], 'export', index);
  } else if (line.match(/^(?:export\s+)?type\s+([A-Za-z_$][\w$]*)\b/)) {
    const typeMatch = line.match(/^(?:export\s+)?type\s+([A-Za-z_$][\w$]*)\b/);
    if (!typeMatch) return;
    addSymbol(typeMatch[1], 'type', index, line, isExported);
    excludedCalls.add(typeMatch[1]);
    if (isExported) addReference(typeMatch[1], 'export', index);
  } else if (line.match(/^(?:export\s+)?(?:const|let|var)\s+([A-Za-z_$][\w$]*)\s*(?::[^=]+)?=/)) {
    const variableMatch = line.match(/^(?:export\s+)?(?:const|let|var)\s+([A-Za-z_$][\w$]*)\s*(?::[^=]+)?=/);
    if (!variableMatch) return;
    const kind: CodeSymbolKind = /=>|\bfunction\b/.test(line) ? 'function' : 'variable';
    excludedCalls.add(variableMatch[1]);
    if (!/^\s/.test(originalLine) || isExported) {
      addSymbol(variableMatch[1], kind, index, line, isExported);
      if (isExported) addReference(variableMatch[1], 'export', index);
    }
  } else {
    const methodMatch = line.match(/^(?:public\s+|private\s+|protected\s+|static\s+|readonly\s+|async\s+|get\s+|set\s+)*([A-Za-z_$][\w$]*)\s*\([^;]*\)\s*(?::\s*[^={]+)?\s*\{/);
    if (methodMatch && !CONTROL_WORDS.has(methodMatch[1])) {
      addSymbol(methodMatch[1], 'method', index, line, false);
      excludedCalls.add(methodMatch[1]);
    }
  }

  extractJsEmbeddedMethodSymbols(line, index, addSymbol, excludedCalls);
  extractCallReferences(line, index, 'javascript', addReference, excludedCalls);
}

function extractPythonLine(
  line: string,
  rawLine: string,
  index: number,
  insideClass: boolean,
  addSymbol: AddSymbol,
  addReference: AddReference
): void {
  const excludedCalls = new Set<string>();

  const fromMatch = line.match(/^from\s+([A-Za-z_][\w.]*|\.+[A-Za-z_][\w.]*)\s+import\s+(.+)/);
  if (fromMatch) addReference(fromMatch[1], 'import', index, { imported: fromMatch[2] });

  const importMatch = line.match(/^import\s+(.+)/);
  if (importMatch) {
    for (const target of importMatch[1].split(',')) {
      addReference(target.replace(/\s+as\s+\w+$/, ''), 'import', index);
    }
  }

  for (const exportMatch of line.matchAll(/__all__\s*=\s*\[([^\]]*)\]/g)) {
    for (const nameMatch of exportMatch[1].matchAll(/['"]([A-Za-z_][\w]*)['"]/g)) {
      addReference(nameMatch[1], 'export', index);
    }
  }

  const functionMatch = line.match(/^(?:async\s+)?def\s+([A-Za-z_][\w]*)\s*\(/);
  if (functionMatch) {
    addSymbol(functionMatch[1], insideClass ? 'method' : 'function', index, line, !functionMatch[1].startsWith('_'));
    excludedCalls.add(functionMatch[1]);
  } else if (line.match(/^class\s+([A-Za-z_][\w]*)\b/)) {
    const classMatch = line.match(/^class\s+([A-Za-z_][\w]*)\b/);
    if (!classMatch) return;
    addSymbol(classMatch[1], 'class', index, line, !classMatch[1].startsWith('_'));
    excludedCalls.add(classMatch[1]);
    const bases = line.match(/^class\s+[A-Za-z_][\w]*\s*\(([^)]*)\)/);
    if (bases) addReferenceList(bases[1], 'inheritance', index, addReference);
  }

  extractCallReferences(rawLine, index, 'python', addReference, excludedCalls);
}

function extractRustLine(
  line: string,
  index: number,
  addSymbol: AddSymbol,
  addReference: AddReference
): void {
  const excludedCalls = new Set<string>();
  const useMatch = line.match(/^(?:pub\s+)?use\s+(.+?);?$/);
  if (useMatch) {
    addReference(useMatch[1], 'import', index);
    if (line.startsWith('pub ')) addReference(useMatch[1], 'export', index);
  }

  const modMatch = line.match(/^(?:pub\s+)?mod\s+([A-Za-z_][\w]*)\s*;?/);
  if (modMatch) {
    addSymbol(modMatch[1], 'module', index, line, line.startsWith('pub '));
    addReference(modMatch[1], 'module', index);
    if (line.startsWith('pub ')) addReference(modMatch[1], 'export', index);
    excludedCalls.add(modMatch[1]);
  }

  const symbolMatch = line.match(/^(?:pub(?:\([^)]*\))?\s+)?(?:async\s+)?(fn|struct|enum|trait|const|static)\s+([A-Za-z_][\w]*)\b/);
  if (symbolMatch) {
    const kindMap: Record<string, CodeSymbolKind> = {
      fn: 'function',
      struct: 'struct',
      enum: 'enum',
      trait: 'trait',
      const: 'constant',
      static: 'variable',
    };
    addSymbol(symbolMatch[2], kindMap[symbolMatch[1]], index, line, line.startsWith('pub'));
    excludedCalls.add(symbolMatch[2]);
    if (line.startsWith('pub')) addReference(symbolMatch[2], 'export', index);
  }

  extractCallReferences(line, index, 'rust', addReference, excludedCalls);
}

function extractGoLine(
  line: string,
  index: number,
  addSymbol: AddSymbol,
  addReference: AddReference
): void {
  const excludedCalls = new Set<string>();
  const importMatch = line.match(/^import\s+(?:\w+\s+)?["`]([^"`]+)["`]/);
  if (importMatch) addReference(importMatch[1], 'import', index);
  const blockImportMatch = line.match(/^(?:\w+\s+)?["`]([^"`]+)["`]$/);
  if (blockImportMatch) addReference(blockImportMatch[1], 'import', index);

  const methodMatch = line.match(/^func\s+\([^)]*\)\s+([A-Za-z_][\w]*)\s*\(/);
  if (methodMatch) {
    addSymbol(methodMatch[1], 'method', index, line, /^[A-Z]/.test(methodMatch[1]));
    excludedCalls.add(methodMatch[1]);
    if (/^[A-Z]/.test(methodMatch[1])) addReference(methodMatch[1], 'export', index);
  } else if (line.match(/^func\s+([A-Za-z_][\w]*)\s*\(/)) {
    const functionMatch = line.match(/^func\s+([A-Za-z_][\w]*)\s*\(/);
    if (!functionMatch) return;
    addSymbol(functionMatch[1], 'function', index, line, /^[A-Z]/.test(functionMatch[1]));
    excludedCalls.add(functionMatch[1]);
    if (/^[A-Z]/.test(functionMatch[1])) addReference(functionMatch[1], 'export', index);
  } else if (line.match(/^type\s+([A-Za-z_][\w]*)\s+(struct|interface)\b/)) {
    const typeMatch = line.match(/^type\s+([A-Za-z_][\w]*)\s+(struct|interface)\b/);
    if (!typeMatch) return;
    addSymbol(typeMatch[1], typeMatch[2] === 'interface' ? 'interface' : 'struct', index, line, /^[A-Z]/.test(typeMatch[1]));
    excludedCalls.add(typeMatch[1]);
    if (/^[A-Z]/.test(typeMatch[1])) addReference(typeMatch[1], 'export', index);
  } else if (line.match(/^(?:var|const)\s+([A-Za-z_][\w]*)\b/)) {
    const variableMatch = line.match(/^(?:var|const)\s+([A-Za-z_][\w]*)\b/);
    if (!variableMatch) return;
    addSymbol(variableMatch[1], line.startsWith('const') ? 'constant' : 'variable', index, line, /^[A-Z]/.test(variableMatch[1]));
    excludedCalls.add(variableMatch[1]);
    if (/^[A-Z]/.test(variableMatch[1])) addReference(variableMatch[1], 'export', index);
  }

  extractCallReferences(line, index, 'go', addReference, excludedCalls);
}

function extractJavaLine(
  line: string,
  index: number,
  addSymbol: AddSymbol,
  addReference: AddReference
): void {
  const excludedCalls = new Set<string>();
  const importMatch = line.match(/^import\s+(?:static\s+)?([A-Za-z_][\w.]*\*?)\s*;/);
  if (importMatch) addReference(importMatch[1], 'import', index);

  extractJavaInheritanceReferences(line, index, addReference);

  const classMatch = line.match(/^(?:public\s+|private\s+|protected\s+|abstract\s+|final\s+)*((?:class)|(?:interface)|(?:enum))\s+([A-Za-z_][\w]*)\b/);
  if (classMatch) {
    const kind = classMatch[1] === 'class' ? 'class' : classMatch[1] === 'interface' ? 'interface' : 'enum';
    addSymbol(classMatch[2], kind, index, line, line.startsWith('public '));
    excludedCalls.add(classMatch[2]);
    if (line.startsWith('public ')) addReference(classMatch[2], 'export', index);
  } else {
    const methodMatch = line.match(/^(?:public\s+|private\s+|protected\s+|static\s+|final\s+|abstract\s+|synchronized\s+)*[A-Za-z_<>\[\], ?]+\s+([A-Za-z_][\w]*)\s*\([^;]*\)\s*(?:throws\s+[^{]+)?\{/);
    if (methodMatch && !CONTROL_WORDS.has(methodMatch[1])) {
      addSymbol(methodMatch[1], 'method', index, line, line.startsWith('public '));
      excludedCalls.add(methodMatch[1]);
      if (line.startsWith('public ')) addReference(methodMatch[1], 'export', index);
    }
  }

  extractCallReferences(line, index, 'java', addReference, excludedCalls);
}

function extractJsExportReferences(line: string, index: number, addReference: AddReference): void {
  const moduleExport = line.match(/^export\s+(?:type\s+)?\{([^}]+)\}(?:\s+from\s+['"]([^'"]+)['"])?/);
  if (moduleExport) {
    for (const name of splitExportList(moduleExport[1])) {
      addReference(name, 'export', index);
    }
    if (moduleExport[2]) addReference(moduleExport[2], 'export', index, { exports: splitExportList(moduleExport[1]) });
  }

  const starExport = line.match(/^export\s+\*\s+from\s+['"]([^'"]+)['"]/);
  if (starExport) addReference(starExport[1], 'export', index, { all: true });

  const defaultExport = line.match(/^export\s+default\s+([A-Za-z_$][\w$]*)\b/);
  if (defaultExport && !CONTROL_WORDS.has(defaultExport[1])) {
    addReference(defaultExport[1], 'export', index, { default: true });
  }
}

function extractJsInheritanceReferences(line: string, index: number, addReference: AddReference): void {
  const extendsMatch = line.match(/\bextends\s+([A-Za-z_$][\w$]*(?:\.[A-Za-z_$][\w$]*)?)/);
  if (extendsMatch) addReference(extendsMatch[1], 'inheritance', index);

  const implementsMatch = line.match(/\bimplements\s+([^{]+)/);
  if (implementsMatch) addReferenceList(implementsMatch[1], 'inheritance', index, addReference);
}

function extractJsEmbeddedMethodSymbols(
  line: string,
  index: number,
  addSymbol: AddSymbol,
  excludedCalls: Set<string>
): void {
  const methodPattern = /\b([A-Za-z_$][\w$]*)\s*\([^;{}]*\)\s*(?::\s*[^={]+)?\s*\{/g;
  for (const match of line.matchAll(methodPattern)) {
    const name = match[1];
    const prefix = line.slice(Math.max(0, match.index - 24), match.index);
    if (CONTROL_WORDS.has(name) || /\b(?:function|if|for|while|switch|catch)\s+$/.test(prefix)) continue;
    addSymbol(name, 'method', index, line, false);
    excludedCalls.add(name);
  }
}

function extractJavaInheritanceReferences(line: string, index: number, addReference: AddReference): void {
  const extendsMatch = line.match(/\bextends\s+([A-Za-z_][\w.]*)/);
  if (extendsMatch) addReference(extendsMatch[1], 'inheritance', index);

  const implementsMatch = line.match(/\bimplements\s+([^{]+)/);
  if (implementsMatch) addReferenceList(implementsMatch[1], 'inheritance', index, addReference);
}

function extractCallReferences(
  line: string,
  index: number,
  language: string,
  addReference: AddReference,
  excludedNames: Set<string> = new Set()
): void {
  const code = stripComments(stripStringLiterals(line), language);
  const callPattern = /\b([A-Za-z_$][\w$]*(?:(?:\.|::)[A-Za-z_$][\w$]*)*)\s*\(/g;
  for (const match of code.matchAll(callPattern)) {
    const target = match[1];
    const root = target.split(/\.|::/)[0];
    const leaf = target.split(/\.|::/).pop() ?? target;
    const lowerRoot = root.toLowerCase();
    const lowerLeaf = leaf.toLowerCase();
    const prefix = code.slice(Math.max(0, match.index - 18), match.index);
    if (/\b(?:function|def|fn|func|class|interface|type)\s+$/.test(prefix)) continue;
    if (excludedNames.has(target) || excludedNames.has(leaf)) continue;
    if (IGNORED_CALL_TARGETS.has(lowerRoot) || IGNORED_CALL_TARGETS.has(lowerLeaf)) continue;
    if (target.startsWith('this.') || target.startsWith('self.')) {
      addReference(leaf, 'call', index, { receiver: target.split(/\.|::/)[0] });
      continue;
    }
    addReference(target, 'call', index);
  }
}

function filterLocalCallReferences(references: CodeReference[], symbols: CodeSymbol[]): CodeReference[] {
  const localSymbolNames = new Set(symbols.map((symbol) => symbol.normalizedName));
  return references.filter((reference) =>
    reference.kind !== 'call' || !localSymbolNames.has(normalizeSymbolName(referenceLeafName(reference.target)))
  );
}

function referenceLeafName(target: string): string {
  return target.split(/\.|::/).pop() ?? target;
}

function addReferenceList(
  value: string,
  kind: CodeReferenceKind,
  index: number,
  addReference: AddReference
): void {
  for (const part of value.split(',')) {
    const target = part
      .replace(/\bas\b\s+[A-Za-z_$][\w$]*/g, '')
      .replace(/\bextends\b|\bimplements\b/g, '')
      .replace(/[<>{}()[\];]/g, ' ')
      .trim()
      .split(/\s+/)[0];
    if (target) addReference(target, kind, index);
  }
}

function splitExportList(value: string): string[] {
  return value
    .split(',')
    .map((part) => part.trim().replace(/^type\s+/, '').split(/\s+as\s+/)[0].trim())
    .filter(Boolean);
}

function stripStringLiterals(value: string): string {
  return value
    .replace(/'(?:\\.|[^'\\])*'/g, "''")
    .replace(/"(?:\\.|[^"\\])*"/g, '""')
    .replace(/`(?:\\.|[^`\\])*`/g, '``');
}

function stripComments(value: string, language: string): string {
  if (language === 'python') return value.replace(/#.*/, '');
  return value.replace(/\/\/.*/, '');
}

function prunePythonClassStack(classIndents: number[], line: string): void {
  const trimmed = line.trim();
  if (trimmed.length === 0) return;
  const indent = leadingSpaces(line);
  while (classIndents.length > 0 && indent <= classIndents[classIndents.length - 1]) {
    classIndents.pop();
  }
}

function findBlockEndLine(lines: string[], startIndex: number, language?: string): number {
  const startLine = lines[startIndex] ?? '';
  if (language === 'python' && /^\s*(?:async\s+)?(?:def|class)\s+/.test(startLine)) {
    const startIndent = leadingSpaces(startLine);
    for (let i = startIndex + 1; i < lines.length; i++) {
      const line = lines[i];
      if (line.trim().length === 0) continue;
      if (leadingSpaces(line) <= startIndent) return i;
    }
    return lines.length;
  }

  let depth = 0;
  let sawBrace = false;
  for (let i = startIndex; i < lines.length; i++) {
    for (const char of lines[i]) {
      if (char === '{') {
        depth++;
        sawBrace = true;
      } else if (char === '}') {
        depth--;
      }
    }
    if (sawBrace && depth <= 0) return i + 1;
  }
  return startIndex + 1;
}

function leadingSpaces(value: string): number {
  return value.length - value.trimStart().length;
}

function findPythonScript(): string | null {
  const fromCwd = join(process.cwd(), 'scripts', 'structural-indexer.py');
  if (existsSync(fromCwd)) return fromCwd;

  const here = dirname(fileURLToPath(import.meta.url));
  const fromCompiled = join(here, '..', '..', 'scripts', 'structural-indexer.py');
  if (existsSync(fromCompiled)) return fromCompiled;

  const fromSource = join(here, '..', '..', '..', 'scripts', 'structural-indexer.py');
  if (existsSync(fromSource)) return fromSource;
  return null;
}

interface PythonExtractorResponse {
  symbols: CodeSymbol[];
  references: CodeReference[];
}

function runPythonStructuralExtractor(
  python: string,
  script: string,
  text: string,
  language: string,
  filePath: string | undefined,
  timeoutMs: number
): Promise<PythonExtractorResponse> {
  return new Promise((resolve, reject) => {
    const child = spawn(python, [script], { stdio: ['pipe', 'pipe', 'pipe'] });
    const id = randomUUID();
    let stdout = '';
    let stderr = '';
    const timer = setTimeout(() => {
      child.kill('SIGKILL');
      reject(new Error('structural extractor timed out'));
    }, timeoutMs);

    child.stdout.setEncoding('utf-8');
    child.stderr.setEncoding('utf-8');
    child.stdout.on('data', (chunk) => { stdout += chunk; });
    child.stderr.on('data', (chunk) => { stderr += chunk; });
    child.on('error', (error) => {
      clearTimeout(timer);
      reject(error);
    });
    child.on('close', (code) => {
      clearTimeout(timer);
      if (code !== 0) {
        reject(new Error(stderr || `structural extractor exited ${code}`));
        return;
      }
      try {
        const response = JSON.parse(stdout) as {
          id?: string;
          result?: PythonExtractorResponse;
          error?: { message?: string };
        };
        if (response.id !== id || !response.result) {
          reject(new Error(response.error?.message ?? 'invalid structural extractor response'));
          return;
        }
        resolve(response.result);
      } catch (error) {
        reject(error);
      }
    });

    child.stdin.end(JSON.stringify({
      jsonrpc: '2.0',
      id,
      method: 'extract',
      params: { text, language, path: filePath },
    }));
  });
}

function normalizeSymbol(symbol: CodeSymbol, filePath: string | undefined, language: string): CodeSymbol {
  return {
    ...symbol,
    id: symbol.id ?? randomUUID(),
    path: symbol.path ?? filePath,
    language: symbol.language ?? language,
    normalizedName: symbol.normalizedName || normalizeSymbolName(symbol.name),
    startLine: symbol.startLine || 1,
    endLine: symbol.endLine || symbol.startLine || 1,
    isExported: Boolean(symbol.isExported),
    metadata: symbol.metadata ?? {},
  };
}

function normalizeReference(reference: CodeReference, filePath: string | undefined, language: string): CodeReference {
  return {
    ...reference,
    id: reference.id ?? randomUUID(),
    path: reference.path ?? filePath,
    language: reference.language ?? language,
    normalizedTarget: reference.normalizedTarget || normalizeIdentifier(reference.target),
    startLine: reference.startLine || 1,
    endLine: reference.endLine || reference.startLine || 1,
    metadata: reference.metadata ?? {},
  };
}

function mergeSymbols(primary: CodeSymbol[], fallback: CodeSymbol[]): CodeSymbol[] {
  const merged: CodeSymbol[] = [];
  const positions = new Map<string, number>();
  for (const symbol of [...primary, ...fallback]) {
    const key = `${symbol.normalizedName || normalizeSymbolName(symbol.name)}:${symbol.startLine}`;
    const existingIndex = positions.get(key);
    if (existingIndex !== undefined) {
      const existing = merged[existingIndex];
      if (shouldReplaceMergedSymbol(existing, symbol)) {
        merged[existingIndex] = symbol;
      }
      continue;
    }
    positions.set(key, merged.length);
    merged.push(symbol);
  }
  return merged.sort((a, b) => a.startLine - b.startLine || a.name.localeCompare(b.name));
}

function shouldReplaceMergedSymbol(existing: CodeSymbol, candidate: CodeSymbol): boolean {
  if (existing.kind === 'function' && candidate.kind === 'method') return true;
  if (!existing.isExported && candidate.isExported) return true;
  return false;
}

function mergeReferences(primary: CodeReference[], fallback: CodeReference[]): CodeReference[] {
  const merged: CodeReference[] = [];
  const seen = new Set<string>();
  for (const reference of [...primary, ...fallback]) {
    const key = `${reference.kind}:${reference.normalizedTarget || normalizeIdentifier(reference.target)}:${reference.startLine}`;
    if (seen.has(key)) continue;
    seen.add(key);
    merged.push(reference);
  }
  return merged.sort((a, b) => a.startLine - b.startLine || a.target.localeCompare(b.target));
}

import type { SymbolInfo } from '../types/index.js';
import { extractStructureFallback } from './structural-indexer.js';

const SYMBOL_INFO_KINDS = new Set<SymbolInfo['kind']>([
  'function',
  'class',
  'interface',
  'type',
  'variable',
  'method',
]);

export function extractSymbols(
  text: string,
  language?: string,
  filePath?: string
): SymbolInfo[] {
  return extractStructureFallback(text, language, filePath)
    .symbols
    .filter((symbol): symbol is typeof symbol & { kind: SymbolInfo['kind'] } =>
      SYMBOL_INFO_KINDS.has(symbol.kind as SymbolInfo['kind'])
    )
    .map((symbol) => ({
      name: symbol.name,
      kind: symbol.kind,
      line: symbol.startLine,
      filePath,
    }));
}

import type { TokenEstimator } from '../types/index.js';

export class DeterministicTokenEstimator implements TokenEstimator {
  estimate(text: string): number {
    if (!text) return 0;
    return Math.ceil(text.length / 4);
  }

  estimateBatch(texts: string[]): number[] {
    return texts.map((t) => this.estimate(t));
  }
}

export { SQLiteRepository, createRepository } from './repository.js';
export { MIGRATIONS, CURRENT_VERSION } from './schema.js';
export { BruteForceVectorIndex, tryCreateSqliteVecIndex } from './vector-index.js';
export type { VectorIndex, VectorSearchResult } from './vector-index.js';

import type {
  CodeReference,
  CodeSymbol,
  ContextChunk,
  ContextFilter,
  ContextTier,
  DependencyLink,
  CompressionResult,
  StructuralQuery,
  StructuralSearchResult,
  StorageProvider,
} from '../types/index.js';
import { randomUUID } from 'node:crypto';
import Database from 'better-sqlite3';
import { mkdirSync } from 'node:fs';
import { dirname } from 'node:path';
import { MIGRATIONS, CURRENT_VERSION } from './schema.js';
import { cosineSimilarity } from '../providers/deterministic-embedding.js';
import type { VectorIndex } from './vector-index.js';
import { BruteForceVectorIndex, tryCreateSqliteVecIndex, VEC_META_TABLE } from './vector-index.js';

export class SQLiteRepository implements StorageProvider {
  private db: Database.Database;
  private vectorIndex: VectorIndex | null = null;

  constructor(dbPath: string = './data/spacefolding.db') {
    mkdirSync(dirname(dbPath), { recursive: true });
    this.db = new Database(dbPath);
    this.db.pragma('journal_mode = WAL');
    this.db.pragma('foreign_keys = ON');
  }

  init(): void {
    const userVersion = this.db.pragma('user_version', { simple: true }) as number;
    for (const migration of MIGRATIONS) {
      if (migration.version > userVersion) {
        for (const stmt of migration.up) {
          this.db.exec(stmt);
        }
      }
    }
    this.db.pragma(`user_version = ${CURRENT_VERSION}`);
  }

  /** Initialise the vector index. Tries sqlite-vec first, falls back to in-memory brute-force. */
  initVectorIndex(dimensions: number = 384): void {
    // Try sqlite-vec extension
    const vecIndex = tryCreateSqliteVecIndex(this.db, dimensions);
    if (vecIndex) {
      this.vectorIndex = vecIndex;
      return;
    }

    // Fallback: in-memory brute-force cache hydrated from existing embeddings
    const bfIndex = new BruteForceVectorIndex(dimensions);
    bfIndex.loadFromDb(this.db);
    this.vectorIndex = bfIndex;
  }

  storeChunk(chunk: ContextChunk): void {
    const existing = this.db
      .prepare('SELECT text FROM chunks WHERE id = ?')
      .get(chunk.id) as { text: string } | undefined;
    const textChanged = existing !== undefined && existing.text !== chunk.text;

    this.db
      .prepare(
        `INSERT INTO chunks (id, source, type, text, timestamp, path, language, tokensEstimate, parentId, metadata)
         VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)
         ON CONFLICT(id) DO UPDATE SET
           source = excluded.source,
           type = excluded.type,
           text = excluded.text,
           timestamp = excluded.timestamp,
           path = excluded.path,
           language = excluded.language,
           tokensEstimate = excluded.tokensEstimate,
           parentId = excluded.parentId,
           metadata = excluded.metadata`
      )
      .run(
        chunk.id,
        chunk.source,
        chunk.type,
        chunk.text,
        chunk.timestamp,
        chunk.path ?? null,
        chunk.language ?? null,
        chunk.tokensEstimate,
        chunk.parentId ?? null,
        JSON.stringify(chunk.metadata)
      );

    if (textChanged) {
      this.deleteEmbedding(chunk.id);
      this.deleteCodeStructure(chunk.id);
    }
  }

  getChunk(id: string): ContextChunk | null {
    const row = this.db
      .prepare('SELECT * FROM chunks WHERE id = ?')
      .get(id) as Row | undefined;
    return row ? rowToChunk(row) : null;
  }

  queryChunks(filter: ContextFilter): ContextChunk[] {
    const clauses: string[] = [];
    const params: unknown[] = [];

    if (filter.source !== undefined) {
      clauses.push('c.source = ?');
      params.push(filter.source);
    }
    if (filter.type !== undefined) {
      clauses.push('c.type = ?');
      params.push(filter.type);
    }
    if (filter.path !== undefined) {
      clauses.push('c.path = ?');
      params.push(filter.path);
    }
    if (filter.textContains !== undefined) {
      clauses.push('c.text LIKE ?');
      params.push(`%${filter.textContains}%`);
    }
    if (filter.tier !== undefined) {
      clauses.push(`EXISTS (
        SELECT 1
        FROM routing_history rh
        WHERE rh.chunkId = c.id
          AND rh.id = (
            SELECT rh2.id
            FROM routing_history rh2
            WHERE rh2.chunkId = c.id
            ORDER BY rh2.timestamp DESC, rh2.id DESC
            LIMIT 1
          )
          AND rh.tier = ?
      )`);
      params.push(filter.tier);
    }

    const where = clauses.length > 0 ? `WHERE ${clauses.join(' AND ')}` : '';
    const rows = this.db
      .prepare(`SELECT c.* FROM chunks c ${where}`)
      .all(...params) as Row[];
    return rows.map(rowToChunk);
  }

  getAllChunks(): ContextChunk[] {
    const rows = this.db.prepare('SELECT * FROM chunks').all() as Row[];
    return rows.map(rowToChunk);
  }

  updateChunk(chunk: ContextChunk): void {
    this.storeChunk(chunk); // INSERT OR REPLACE
  }

  deleteChunk(id: string): void {
    this.deleteCodeStructure(id);
    this.deleteEmbedding(id);
    this.db.prepare('DELETE FROM chunks WHERE id = ?').run(id);
    this.removeAllDependenciesForChunk(id);
  }

  storeDependency(link: DependencyLink): void {
    this.db
      .prepare(
        `INSERT OR REPLACE INTO dependencies (fromId, toId, type, weight)
         VALUES (?, ?, ?, ?)`
      )
      .run(link.fromId, link.toId, link.type, link.weight);
  }

  removeDependency(fromId: string, toId: string, type: DependencyLink['type']): void {
    this.db
      .prepare('DELETE FROM dependencies WHERE fromId = ? AND toId = ? AND type = ?')
      .run(fromId, toId, type);
  }

  removeAllDependenciesForChunk(chunkId: string): void {
    this.db
      .prepare('DELETE FROM dependencies WHERE fromId = ? OR toId = ?')
      .run(chunkId, chunkId);
  }

  getDependencies(chunkId: string): DependencyLink[] {
    const rows = this.db
      .prepare(
        'SELECT * FROM dependencies WHERE fromId = ? OR toId = ?'
      )
      .all(chunkId, chunkId) as DepRow[];
    return rows.map((r) => ({
      fromId: r.fromId,
      toId: r.toId,
      type: r.type as DependencyLink['type'],
      weight: r.weight,
    }));
  }

  storeRoutingDecision(
    chunkId: string,
    tier: ContextTier,
    score: number,
    reasons: string[],
    taskText: string
  ): void {
    this.db
      .prepare(
        `INSERT INTO routing_history (chunkId, tier, score, reasons, taskText, timestamp)
         VALUES (?, ?, ?, ?, ?, ?)`
      )
      .run(chunkId, tier, score, JSON.stringify(reasons), taskText, Date.now());
  }

  storeCompression(result: CompressionResult & { id: string; taskText: string }): void {
    this.db
      .prepare(
        `INSERT OR REPLACE INTO compression_cache (id, taskText, summary, retainedFacts, retainedConstraints, sourceChunkIds, timestamp)
         VALUES (?, ?, ?, ?, ?, ?, ?)`
      )
      .run(
        result.id,
        result.taskText,
        result.summary,
        JSON.stringify(result.retainedFacts),
        JSON.stringify(result.retainedConstraints),
        JSON.stringify(result.sourceChunkIds),
        Date.now()
      );
  }

  getCompression(id: string): CompressionResult | null {
    const row = this.db
      .prepare('SELECT * FROM compression_cache WHERE id = ?')
      .get(id) as CompRow | undefined;
    if (!row) return null;
    return {
      summary: row.summary,
      retainedFacts: JSON.parse(row.retainedFacts),
      retainedConstraints: JSON.parse(row.retainedConstraints),
      sourceChunkIds: JSON.parse(row.sourceChunkIds),
    };
  }

  getChunkCount(): number {
    const row = this.db.prepare('SELECT COUNT(*) as count FROM chunks').get() as {
      count: number;
    };
    return row.count;
  }

  /** Find a chunk by a key-value pair in its JSON metadata */
  findChunkByMetadata(key: string, value: string): ContextChunk | null {
    const rows = this.db
      .prepare('SELECT * FROM chunks')
      .all() as Row[];
    for (const row of rows) {
      try {
        const meta = JSON.parse(row.metadata);
        if (meta[key] === value) return rowToChunk(row);
      } catch { continue; }
    }
    return null;
  }

  /** Find a previously ingested chunk by content hash, scoped by path for files. */
  findChunkByContentHash(contentHash: string, path?: string): ContextChunk | null {
    const rows = this.db
      .prepare(path ? 'SELECT * FROM chunks WHERE path = ?' : 'SELECT * FROM chunks WHERE path IS NULL')
      .all(...(path ? [path] : [])) as Row[];
    for (const row of rows) {
      try {
        const meta = JSON.parse(row.metadata);
        if (meta.contentHash === contentHash) return rowToChunk(row);
      } catch { continue; }
    }
    return null;
  }

  // ── Structural Code Index ─────────────────────────────────────

  storeCodeStructure(chunkId: string, symbols: CodeSymbol[], references: CodeReference[]): void {
    const insertSymbol = this.db.prepare(
      `INSERT INTO code_symbols (
        id, chunkId, path, language, name, normalizedName, kind, signature,
        startLine, endLine, isExported, metadata
      ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`
    );
    const insertReference = this.db.prepare(
      `INSERT INTO code_references (
        id, chunkId, path, language, target, normalizedTarget, kind,
        startLine, endLine, metadata
      ) VALUES (?, ?, ?, ?, ?, ?, ?, ?, ?, ?)`
    );

    const tx = this.db.transaction(() => {
      this.deleteCodeStructure(chunkId);
      for (const symbol of symbols) {
        insertSymbol.run(
          symbol.id ?? randomUUID(),
          chunkId,
          symbol.path ?? '',
          symbol.language ?? '',
          symbol.name,
          symbol.normalizedName,
          symbol.kind,
          symbol.signature ?? null,
          symbol.startLine,
          symbol.endLine,
          symbol.isExported ? 1 : 0,
          JSON.stringify(symbol.metadata ?? {})
        );
      }
      for (const reference of references) {
        insertReference.run(
          reference.id ?? randomUUID(),
          chunkId,
          reference.path ?? '',
          reference.language ?? '',
          reference.target,
          reference.normalizedTarget,
          reference.kind,
          reference.startLine,
          reference.endLine,
          JSON.stringify(reference.metadata ?? {})
        );
      }
    });
    tx();
  }

  deleteCodeStructure(chunkId: string): void {
    this.db.prepare('DELETE FROM code_symbols WHERE chunkId = ?').run(chunkId);
    this.db.prepare('DELETE FROM code_references WHERE chunkId = ?').run(chunkId);
  }

  getCodeSymbols(chunkId: string): CodeSymbol[] {
    const rows = this.db
      .prepare('SELECT * FROM code_symbols WHERE chunkId = ? ORDER BY startLine, name')
      .all(chunkId) as CodeSymbolRow[];
    return rows.map(rowToCodeSymbol);
  }

  getCodeReferences(chunkId: string): CodeReference[] {
    const rows = this.db
      .prepare('SELECT * FROM code_references WHERE chunkId = ? ORDER BY startLine, target')
      .all(chunkId) as CodeReferenceRow[];
    return rows.map(rowToCodeReference);
  }

  getAllCodeSymbols(): CodeSymbol[] {
    const rows = this.db
      .prepare('SELECT * FROM code_symbols ORDER BY path, startLine, name')
      .all() as CodeSymbolRow[];
    return rows.map(rowToCodeSymbol);
  }

  getAllCodeReferences(): CodeReference[] {
    const rows = this.db
      .prepare('SELECT * FROM code_references ORDER BY path, startLine, target')
      .all() as CodeReferenceRow[];
    return rows.map(rowToCodeReference);
  }

  hasCodeStructure(): boolean {
    const row = this.db
      .prepare('SELECT COUNT(*) as count FROM code_symbols')
      .get() as { count: number };
    return row.count > 0;
  }

  searchByStructure(query: StructuralQuery, topK: number = 50): StructuralSearchResult[] {
    const scores = new Map<string, StructuralSearchResult>();
    const identifierParts = new Set(query.identifierParts);
    const exactIdentifiers = new Set(
      query.identifiers
        .map((identifier) => normalizeSearchTerm(identifier))
        .filter((identifier) => identifier.length > 2)
    );
    const pathTokens = new Set(query.pathTokens);
    const queryPathParts = new Set([
      ...query.identifierParts,
      ...query.tokens.map((token) => normalizeSearchTerm(token)).filter((token) => token.length > 2),
    ]);
    const quotedTerms = new Set(query.quotedTerms.map((term) => normalizeSearchTerm(term)));
    for (const term of quotedTerms) {
      if (term.length > 2) exactIdentifiers.add(term);
    }

    const lowercaseExactCue = /\b(find|where|locate|show|contains|defined|grep|which\s+file)\b/i.test(query.raw);
    const strongExactIdentifiers = new Set(
      query.identifiers
        .filter((identifier) =>
          /[a-z0-9][A-Z]/.test(identifier) ||
          identifier.includes('_') ||
          /^[A-Z]{2,}$/.test(identifier) ||
          /^[A-Z][a-z0-9]+[A-Z][A-Za-z0-9]*$/.test(identifier) ||
          (lowercaseExactCue && /^[a-z][a-z0-9_$]{5,}$/.test(identifier))
        )
        .map((identifier) => normalizeSearchTerm(identifier))
        .filter((identifier) => identifier.length > 2)
    );
    for (const identifier of exactIdentifiers) {
      if (lowercaseExactCue && /^[a-z][a-z0-9_$]{5,}$/.test(identifier)) {
        strongExactIdentifiers.add(identifier);
      }
    }
    const partialIdentifierTerms = new Set(
      [
        ...query.identifierParts.map((part) => normalizeSearchTerm(part)),
        ...exactIdentifiers,
      ].filter((part) => part.length > 2)
    );

    const addScore = (
      chunkId: string,
      structuralScore: number,
      dependencyBoost: number,
      reason: string,
      flags?: { symbolExact?: boolean; pathExact?: boolean }
    ) => {
      if (structuralScore <= 0 && dependencyBoost <= 0) return;
      const existing = scores.get(chunkId) ?? {
        chunkId,
        score: 0,
        structuralScore: 0,
        dependencyBoost: 0,
        reasons: [],
        symbolExact: false,
        pathExact: false,
      };
      existing.structuralScore += structuralScore;
      existing.dependencyBoost = Math.min(0.12, existing.dependencyBoost + dependencyBoost);
      // Typed match flags are set independently of the reason string, which is
      // capped at 6 entries — so an exact match is never silently lost to the cap.
      if (flags?.symbolExact) existing.symbolExact = true;
      if (flags?.pathExact) existing.pathExact = true;
      if (!existing.reasons.includes(reason) && existing.reasons.length < 6) {
        existing.reasons.push(reason);
      }
      existing.score = existing.structuralScore + existing.dependencyBoost;
      scores.set(chunkId, existing);
    };

    const pathRows = this.db
      .prepare(`SELECT id, path, language FROM chunks WHERE path IS NOT NULL AND path != ''`)
      .all() as Array<{ id: string; path: string; language: string | null }>;
    for (const row of pathRows) {
      const lowerPath = row.path.toLowerCase();
      const lowerPathStem = lowerPath.replace(/\.[^.]+$/, '');
      const basename = lowerPath.split('/').pop() ?? lowerPath;
      const basenameStem = basename.replace(/\.[^.]+$/, '');
      const basenameParts = splitSearchIdentifier(basename.replace(/\.[^.]+$/, ''));

      for (const fragment of query.pathFragments) {
        const lowerFragment = fragment.toLowerCase();
        if (lowerPath === lowerFragment || lowerPath.endsWith(`/${lowerFragment}`)) {
          addScore(row.id, 3.2, 0, `path exact match: ${fragment}`, { pathExact: true });
        } else if (lowerPathStem === lowerFragment || lowerPathStem.endsWith(`/${lowerFragment}`)) {
          addScore(row.id, 2.6, 0, `path stem exact match: ${fragment}`);
        } else if (basenameStem === lowerFragment || basename === lowerFragment) {
          addScore(row.id, 2.4, 0, `filename exact match: ${fragment}`);
        } else if (basename.includes(lowerFragment)) {
          addScore(row.id, 1.8, 0, `filename match: ${fragment}`);
        } else if (lowerPath.includes(lowerFragment)) {
          addScore(row.id, 1.1, 0, `path fragment match: ${fragment}`);
        }
      }

      for (const token of pathTokens) {
        if (token.length > 1 && lowerPath.includes(token)) {
          addScore(row.id, 0.12, 0, `path token match: ${token}`);
        }
      }

      for (const part of queryPathParts) {
        if (part.length <= 2) continue;
        if (basename.includes(part)) {
          addScore(row.id, 0.5, 0, `filename token match: ${part}`);
        } else if (lowerPath.includes(part)) {
          addScore(row.id, 0.25, 0, `path token match: ${part}`);
        } else if (basenameParts.some((basenamePart) => commonPrefixLength(part, basenamePart) >= 4)) {
          addScore(row.id, 0.28, 0, `filename fuzzy match: ${part}`);
        }
      }

      for (const ext of query.extensions) {
        if (lowerPath.endsWith(`.${ext}`)) {
          addScore(row.id, 0.08, 0, `extension match: .${ext}`);
        }
      }
    }

    const symbolRows = this.db
      .prepare('SELECT * FROM code_symbols')
      .all() as CodeSymbolRow[];
    for (const row of symbolRows) {
      const normalizedName = row.normalizedName;
      if (strongExactIdentifiers.has(normalizedName)) {
        const contractBoost = row.kind === 'interface' || row.kind === 'type' ? 0.8 : 0.3;
        addScore(row.chunkId, (row.isExported ? 5.6 : 5.2) + contractBoost, 0, `symbol strong exact match: ${row.name}`);
        continue;
      }
      if (exactIdentifiers.has(normalizedName) || quotedTerms.has(normalizedName)) {
        const contractBoost = row.kind === 'interface' || row.kind === 'type' ? 0.4 : 0;
        addScore(row.chunkId, (row.isExported ? 3.4 : 3.1) + contractBoost, 0, `symbol exact match: ${row.name}`, { symbolExact: true });
        continue;
      }

      let overlap = 0;
      for (const part of splitSearchIdentifier(row.name)) {
        if (identifierParts.has(part)) overlap++;
      }
      if (overlap > 0) {
        addScore(
          row.chunkId,
          Math.min(0.75, overlap * 0.25) + (row.isExported ? 0.05 : 0),
          0,
          `symbol token match: ${row.name}`
        );
      }

      for (const identifier of partialIdentifierTerms) {
        if (identifier.length > 4 && normalizedName.includes(identifier)) {
          const partialScore = strongExactIdentifiers.has(identifier) ? 0.75 : 0.4;
          addScore(row.chunkId, partialScore, 0, `symbol partial match: ${row.name}`);
        }
      }
    }

    const referenceRows = this.db
      .prepare('SELECT * FROM code_references')
      .all() as CodeReferenceRow[];
    for (const row of referenceRows) {
      const target = row.normalizedTarget;
      for (const identifier of exactIdentifiers) {
        if (identifier.length <= 2) continue;
        if (target === identifier) {
          if (strongExactIdentifiers.has(identifier)) {
            addScore(row.chunkId, 1.4, 0.1, `direct reference strong exact match: ${row.target}`);
          } else {
            addScore(row.chunkId, 0.7, 0.08, `direct reference exact match: ${row.target}`);
          }
        } else if (identifier.length > 4 && target.includes(identifier)) {
          if (strongExactIdentifiers.has(identifier)) {
            addScore(row.chunkId, 0.5, 0.05, `direct reference strong partial match: ${row.target}`);
          } else {
            addScore(row.chunkId, 0.22, 0.03, `direct reference partial match: ${row.target}`);
          }
        }
      }
      for (const part of identifierParts) {
        if (part.length > 2 && target.includes(part)) {
          addScore(row.chunkId, 0.08, 0.02, `reference token boost: ${row.target}`);
        }
      }
    }

    return [...scores.values()]
      .map((result) => ({
        ...result,
        score: result.structuralScore + result.dependencyBoost,
      }))
      .filter((result) => result.score > 0)
      .sort((a, b) => b.score - a.score)
      .slice(0, topK);
  }

  // ── Vector Store ──────────────────────────────────────────

  storeEmbedding(chunkId: string, embedding: number[], model: string): void {
    const buffer = new Float32Array(embedding).buffer;
    this.db
      .prepare(
        `INSERT OR REPLACE INTO chunk_embeddings (chunkId, embedding, model, dimensions, timestamp)
         VALUES (?, ?, ?, ?, ?)`
      )
      .run(chunkId, Buffer.from(buffer), model, embedding.length, Date.now());
    if (this.vectorIndex && this.vectorIndex.dimensions() !== embedding.length) {
      this.initVectorIndex(embedding.length);
      return;
    }
    if (this.vectorIndex) {
      this.vectorIndex.add(chunkId, embedding);
    }
  }

  private deleteEmbedding(chunkId: string): void {
    this.db.prepare('DELETE FROM chunk_embeddings WHERE chunkId = ?').run(chunkId);
    if (this.vectorIndex) {
      this.vectorIndex.remove(chunkId);
    }
  }

  getEmbedding(chunkId: string): { embedding: number[]; model: string } | null {
    const row = this.db
      .prepare('SELECT embedding, model, dimensions FROM chunk_embeddings WHERE chunkId = ?')
      .get(chunkId) as EmbRow | undefined;
    if (!row) return null;
    const float32 = new Float32Array(row.embedding.buffer, row.embedding.byteOffset, row.dimensions);
    return { embedding: Array.from(float32), model: row.model };
  }

  /** Vector similarity search — uses the ANN index if available, otherwise falls back to brute-force */
  searchByVector(queryEmbedding: number[], topK: number = 50): { chunkId: string; score: number }[] {
    if (queryEmbedding.length === 0) return [];
    if (!this.vectorIndex || this.vectorIndex.dimensions() !== queryEmbedding.length) {
      this.initVectorIndex(queryEmbedding.length);
    }
    if (this.vectorIndex) {
      return this.vectorIndex.search(queryEmbedding, topK);
    }

    // Legacy brute-force: loads ALL embeddings from DB each time
    const rows = this.db
      .prepare('SELECT chunkId, embedding, dimensions FROM chunk_embeddings')
      .all() as Array<{ chunkId: string; embedding: Buffer; dimensions: number }>;

    const results: { chunkId: string; score: number }[] = [];
    for (const row of rows) {
      const vec = Array.from(new Float32Array(row.embedding.buffer, row.embedding.byteOffset, row.dimensions));
      const score = cosineSimilarity(queryEmbedding, vec);
      results.push({ chunkId: row.chunkId, score });
    }

    results.sort((a, b) => b.score - a.score);
    return results.slice(0, topK);
  }

  /** Check if embeddings exist for a model */
  hasEmbeddings(model?: string): boolean {
    if (model) {
      const row = this.db
        .prepare('SELECT COUNT(*) as count FROM chunk_embeddings WHERE model = ?')
        .get(model) as { count: number };
      return row.count > 0;
    }
    const row = this.db.prepare('SELECT COUNT(*) as count FROM chunk_embeddings').get() as { count: number };
    return row.count > 0;
  }

  /** Get chunk IDs that are missing embeddings for a given model */
  getChunksWithoutEmbeddings(model: string): string[] {
    const rows = this.db
      .prepare(
        `SELECT c.id FROM chunks c
         WHERE NOT EXISTS (
           SELECT 1 FROM chunk_embeddings e WHERE e.chunkId = c.id AND e.model = ?
         )`
      )
      .all(model) as Array<{ id: string }>;
    return rows.map((r) => r.id);
  }

  /**
   * Number of times the derived vec0 cache has been (re)built. Used by tests and
   * ops to confirm the index is reused — not rebuilt — across reopenings at a
   * constant dimension. Returns 0 when sqlite-vec is unavailable (the in-memory
   * brute-force fallback has no persistence to reuse).
   */
  getVectorIndexRebuildCount(): number {
    try {
      const row = this.db
        .prepare(`SELECT value FROM ${VEC_META_TABLE} WHERE key = 'rebuildCount'`)
        .get() as { value: string } | undefined;
      return row ? Number(row.value) : 0;
    } catch {
      return 0;
    }
  }

  // ── Full-Text Search ───────────────────────────────────────

  /** BM25-ranked text search using FTS5 */
  searchByText(query: string, topK: number = 50): { chunkId: string; score: number }[] {
    // Tokenize: lowercase, strip punctuation, remove stop words
    const stopWords = new Set([
      'the', 'and', 'for', 'are', 'but', 'not', 'you', 'all', 'can', 'had', 'her',
      'was', 'one', 'our', 'out', 'has', 'have', 'from', 'been', 'were', 'will',
      'would', 'could', 'should', 'than', 'then', 'into', 'when', 'where', 'which',
      'their', 'that', 'this', 'with', 'does', 'how', 'what', 'why', 'who', 'its',
    ]);
    const words = query
      .toLowerCase()
      .replace(/[^a-z0-9\s]/g, ' ')
      .split(/\s+/)
      .filter((w) => w.length > 2 && !stopWords.has(w));
    if (words.length === 0) return [];

    // Build safe FTS5 OR query with quoted terms
    const ftsQuery = words.map((w) => `"${w}"`).join(' OR ');

    try {
      const rows = this.db
        .prepare(
          `SELECT rowid, text, path, source, type, rank
           FROM chunks_fts
           WHERE chunks_fts MATCH ?
           ORDER BY rank
           LIMIT ?`
        )
        .all(ftsQuery, topK) as Array<{ rowid: number; rank: number }>;

      if (rows.length === 0) return [];

      // Convert FTS5 rowid back to chunk ID
      const chunkRows = this.db
        .prepare('SELECT id, rowid FROM chunks WHERE rowid IN (' + rows.map(() => '?').join(',') + ')')
        .all(...rows.map((r) => r.rowid)) as Array<{ id: string; rowid: number }>;

      const rowidToId = new Map(chunkRows.map((r) => [r.rowid, r.id]));

      return rows
        .map((r) => ({
          chunkId: rowidToId.get(r.rowid) ?? '',
          score: -r.rank, // FTS5 rank is negative BM25, negate for positive score
        }))
        .filter((r) => r.chunkId !== '');
    } catch {
      // FTS5 might not support the query syntax
      return [];
    }
  }

  /** Deterministic lexical fallback over chunk text and paths. */
  searchByLexical(query: string, topK: number = 50): { chunkId: string; score: number }[] {
    const stopWords = new Set([
      'that', 'this', 'with', 'from', 'does', 'have', 'been', 'were', 'will',
      'would', 'could', 'should', 'than', 'then', 'into', 'when', 'where',
      'which', 'their',
    ]);
    const terms = query
      .toLowerCase()
      .replace(/[^\w\s]/g, ' ')
      .split(/\s+/)
      .filter((term) => term.length > 3 && !stopWords.has(term));
    const uniqueTerms = [...new Set(terms)];
    if (uniqueTerms.length === 0) return [];

    const rows = this.db
      .prepare('SELECT id, text, path FROM chunks')
      .all() as Array<{ id: string; text: string; path: string | null }>;

    const scored = rows.map((chunk) => {
      const text = chunk.text.toLowerCase();
      const path = (chunk.path ?? '').toLowerCase();
      let score = 0;
      for (const term of uniqueTerms) {
        if (`${text} ${path}`.includes(term)) score += 2;
        if (path.includes(term)) score += 3;
      }
      return { chunkId: chunk.id, score };
    });

    return scored
      .filter((result) => result.score > 0)
      .sort((a, b) => b.score - a.score)
      .slice(0, topK);
  }

  close(): void {
    this.db.close();
  }
}

// Internal row types
interface Row {
  id: string;
  source: string;
  type: string;
  text: string;
  timestamp: number;
  path: string | null;
  language: string | null;
  tokensEstimate: number;
  parentId: string | null;
  metadata: string;
}

interface DepRow {
  fromId: string;
  toId: string;
  type: string;
  weight: number;
}

interface CompRow {
  id: string;
  taskText: string;
  summary: string;
  retainedFacts: string;
  retainedConstraints: string;
  sourceChunkIds: string;
  timestamp: number;
}

interface EmbRow {
  chunkId: string;
  embedding: Buffer;
